// OFFICIAL ADVERSARY DATABASE (130 entries - Daggerheart Companion/SRD)
// Tier breakdown: T1=53, T2=36, T3=23, T4=18
const monsterManual = {
  "acid_burrower": { env: "Beasts & Solos", name: "Acid Burrower", tier: "1", type: "Solo", diff: 14, atk: "+3", maxHp: 8, maxStress: 3, major: 8, severe: 15, weapon: "Claws", damageType: "Physical", dice: "1d12+2", motives: "burrow, drag away, feed, reposition", experiences: "Tremor Sense +2", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Burrower can be spotlighted up to three times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag stress'>1 Stress</span> <b>Earth Eruption</b>: Mark a Stress to have the Burrower burst out of the ground. All creatures within Very Close range must succeed on an Agility Reaction Roll or be knocked over, making them Vulnerable until they next act.", "<span class='cost-tag'>Action</span> <b>Spit Acid</b>: Make an attack against all targets in front of the Burrower within Close range. Targets the Burrower succeeds against take 2d6 physical damage and must mark an Armor Slot without receiving its benefits (they can still use armor to reduce the damage). If they can't mark an Armor Slot, they must mark an additional HP and you gain a Fear.", "<span class='cost-tag'>Passive</span> <b>Acid Bath</b>: When the Burrower takes Severe damage, all creatures within Close range are bathed in their acidic blood, taking 1d10 physical damage. This splash covers the ground within Very Close range with blood, and all creatures other than the Burrower who move through it take 1d6 physical damage."] },
  "archer_guard": { env: "Settlement Guards", name: "Archer Guard", tier: "1", type: "Ranged", diff: 10, atk: "+1", maxHp: 3, maxStress: 2, major: 4, severe: 8, weapon: "Longbow", damageType: "Physical", dice: "1d8+3", motives: "arrest, close gates, make it through the day, pin down", experiences: "Local Knowledge +3", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Hobbling Shot</b>: Make an attack against a target within Far range. On a success, mark a Stress to deal 1d12+3 physical damage. If the target marks HP from this attack, they have disadvantage on Agility Rolls until they clear at least 1 HP."] },
  "bear": { env: "Beasts & Wilderness", name: "Bear", tier: "1", type: "Bruiser", diff: 14, atk: "+1", maxHp: 7, maxStress: 2, major: 9, severe: 17, weapon: "Claws", damageType: "Physical", dice: "1d8+3", motives: "climb, defend territory, pummel, track", experiences: "Ambusher +3, Keen Senses +2", features: ["<span class='cost-tag'>Passive</span> <b>Overwhelming Force</b>: Targets who mark HP from the Bear's standard attack are knocked back to Very Close range.", "<span class='cost-tag stress'>1 Stress</span> <b>Bite</b>: Mark a Stress to make an attack against a target within Melee range. On a success, deal 3d4+10 physical damage and the target is Restrained until they break free with a successful Strength Roll.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Bear makes a successful attack against a PC, you gain a Fear."] },
  "bladed_guard": { env: "Settlement Guards", name: "Bladed Guard", tier: "1", type: "Standard", diff: 12, atk: "+1", maxHp: 5, maxStress: 2, major: 5, severe: 9, weapon: "Longsword", damageType: "Physical", dice: "1d6+1", motives: "arrest, close gates, make it through the day, pin down", experiences: "Local Knowledge +3", features: ["<span class='cost-tag'>Passive</span> <b>Shield Wall</b>: A creature who tries to move within Very Close range of the Guard must succeed on an Agility Roll. If additional Bladed Guards are standing in a line alongside the first, and each is within Melee range of another guard in the line, the Difficulty increases by the total number of guards in that line.", "<span class='cost-tag stress'>1 Stress</span> <b>Detain</b>: Make an attack against a target within Very Close range. On a success, mark a Stress to Restrain the target until they break free with a successful attack, Finesse Roll, or Strength Roll."] },
  "brawny_zombie": { env: "Undead", name: "Brawny Zombie", tier: "1", type: "Bruiser", diff: 10, atk: "+2", maxHp: 7, maxStress: 4, major: 8, severe: 15, weapon: "Slam", damageType: "Physical", dice: "1d12+3", motives: "crush, destroy, hail debris, slam", experiences: "Collateral Damage +2, Throw +4", features: ["<span class='cost-tag'>Passive</span> <b>Slow</b>: When you spotlight the Zombie and they don't have a token on their stat block, they can't act yet. Place a token on their stat block and describe what they're preparing to do. When you spotlight the Zombie and they have a token on their stat block, clear the token and they can act.", "<span class='cost-tag'>Passive</span> <b>Rend Asunder</b>: Make a standard attack with advantage against a target the Zombie has Restrained. On a success, the attack deals direct damage.", "<span class='cost-tag stress'>2 Stress</span> <b>Rip and Tear</b>: When the Zombies makes a successful standard attack, you can mark a Stress to temporarily Restrain the target and force them to mark 2 Stress."] },
  "cave_ogre": { env: "Beasts & Solos", name: "Cave Ogre", tier: "1", type: "Solo", diff: 13, atk: "+1", maxHp: 8, maxStress: 3, major: 8, severe: 15, weapon: "Club", damageType: "Physical", dice: "1d10+2", motives: "bite off heads, feast, rip limbs, stomp, throw enemies", experiences: "Throw +2", features: ["<span class='cost-tag fear'>1 Fear</span> <b>Ramp Up</b>: You must spend a Fear to spotlight the Ogre. While spotlighted, they can make their standard attack against all targets within range.", "<span class='cost-tag'>Passive</span> <b>Bone Breaker</b>: The Ogre's attacks deal direct damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Hail of Boulders</b>: Mark a Stress to pick up heavy objects and throw them at all targets in front of the Ogre within Far range. Make an attack against these targets. Targets the Ogre succeeds against take 1d10+2 physical damage. If they succeed against more than one target, you gain a Fear.", "<span class='cost-tag'>Passive</span> <b>Rampaging Fury</b>: When the Ogre marks 2 or more HP, they can rampage. Move the Ogre to a point within Close range and deal 2d6+3 direct physical damage to all targets in their path."] },
  "construct": { env: "Arcane Threats", name: "Construct", tier: "1", type: "Solo", diff: 13, atk: "+4", maxHp: 9, maxStress: 4, major: 7, severe: 15, weapon: "Fist Slam", damageType: "Physical", dice: "1d20", motives: "destroy environment, serve creator, smash target, trample groups", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Construct can be spotlighted up to two times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag'>Passive</span> <b>Weak Structure</b>: When the Construct marks HP from physical damage, they must mark an additional HP.", "<span class='cost-tag stress'>1 Stress</span> <b>Trample</b>: Mark a Stress to make an attack against all targets in the Construct's path when they move. Targets the Construct succeeds against take 1d8 physical damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Overload</b>: Before rolling damage for the Construct's attack, you can mark a Stress to gain a +10 bonus to the damage roll. The Construct can then take the spotlight again.", "<span class='cost-tag'>Action</span> <b>Death Quake</b>: When the Construct marks their last HP, the magic powering them ruptures in an explosion of force. Make an attack with advantage against all targets within Very Close range. Targets the Construct succeeds against take 1d12+2 magic damage."] },
  "courtier": { env: "Social & Mercenaries", name: "Courtier", tier: "1", type: "Social", diff: 12, atk: "-4", maxHp: 3, maxStress: 4, major: 4, severe: 8, weapon: "Daggers", damageType: "Physical", dice: "1d4+2", motives: "discredit, gain favor, maneuver, scheme", experiences: "Socialite +3", features: ["<span class='cost-tag stress'>2 Stress</span> <b>Mockery</b>: Mark a Stress to say something mocking and force a target within Close range to make a Presence Reaction Roll (14) to see if they can save face. On a failure, the target must mark 2 Stress and is Vulnerable until the scene ends.", "<span class='cost-tag fear'>1 Fear</span> <b>Scapegoat</b>: Spend a Fear and target a PC. The Courtier convinces a crowd or prominent individual that the target is the cause of their current conflict or misfortune."] },
  "deeproot_defender": { env: "Forest & Fae", name: "Deeproot Defender", tier: "1", type: "Bruiser", diff: 10, atk: "+2", maxHp: 7, maxStress: 3, major: 8, severe: 14, weapon: "Vines", damageType: "Physical", dice: "1d8+3", motives: "ambush, grab, protect, pummel", experiences: "Huge +3", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Ground Slam</b>: Slam the ground, knocking all targets within Very Close range back to Far range. Each target knocked back this way must mark a Stress.", "<span class='cost-tag fear'>1 Fear</span> <b>Grab and Drag</b>: Make an attack against a target within Close range. On a success, spend a Fear to pull them into Melee range, deal 1d6+2 physical damage."] },
  "dire_wolf": { env: "Beasts & Wilderness", name: "Dire Wolf", tier: "1", type: "Skulk", diff: 12, atk: "+2", maxHp: 4, maxStress: 3, major: 5, severe: 9, weapon: "Claws", damageType: "Physical", dice: "1d6+2", motives: "defend territory, harry, protect pack, surround, trail", experiences: "Keen Senses +3", features: ["<span class='cost-tag'>Passive</span> <b>Pack Tactics</b>: If the Wolf makes a successful standard attack and another Dire Wolf is within Melee range of the target, deal 1d6+5 physical damage instead of their standard damage and you gain a Fear.", "<span class='cost-tag stress'>1 Stress</span> <b>Hobbling Strike</b>: Mark a Stress to make an attack against a target within Melee range. On a success, deal 3d4+10 direct physical damage and make them Vulnerable until they clear at least 1 HP."] },
  "giant_mosquitoes": { env: "Beasts & Wilderness", name: "Giant Mosquitoes", tier: "1", type: "Horde", diff: 10, atk: "-2", maxHp: 6, maxStress: 3, major: 5, severe: 9, weapon: "Proboscis", damageType: "Physical", dice: "1d8+3", motives: "fly away, harass, steal blood", experiences: "Camouflage +2", features: ["<span class='cost-tag'>Passive</span> <b>Horde</b>: When the Mosquitoes have marked half or more of their HP, their standard attack deals 1d4+1 physical damage instead.", "<span class='cost-tag'>Passive</span> <b>Flying</b>: While flying, the Mosquitoes have a +2 bonus to their Difficulty.", "<span class='cost-tag stress'>1 Stress</span> <b>Bloodsucker</b>: When the Mosquitoes' attack causes a target to mark HP, you can mark a Stress to force the target to mark an additional HP."] },
  "giant_rat": { env: "Beasts & Wilderness", name: "Giant Rat", tier: "1", type: "Minion", diff: 10, atk: "-4", maxHp: 1, maxStress: 1, major: 0, severe: 0, weapon: "Claws", damageType: "Physical", dice: "1", motives: "burrow, hunger, scavenge, wear down", experiences: "Keen Senses +3", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Rat is defeated when they take any damage. For every 3 damage a PC deals to the Rat, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Giant Rats within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 1 physical damage each. Combine this damage."] },
  "giant_scorpion": { env: "Beasts & Wilderness", name: "Giant Scorpion", tier: "1", type: "Bruiser", diff: 13, atk: "+1", maxHp: 6, maxStress: 3, major: 7, severe: 13, weapon: "Pincers", damageType: "Physical", dice: "1d12+2", motives: "ambush, feed, grapple, poison", experiences: "Camouflage +2", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Double Strike</b>: Mark a Stress to make a standard attack against two targets within Melee range.", "<span class='cost-tag stress'>1 Stress</span> <b>Venomous Stinger</b>: Make an attack against a target within Very Close range. On a success, spend a Fear to deal 1d4+4 physical damage and Poison them until their next rest or they succeed on a Knowledge Roll (16). While Poisoned, the target must roll a d6 before they make an action roll. On a result of 4 or lower, they must mark a Stress.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Scorpion makes a successful attack against a PC, you gain a Fear."] },
  "glass_snake": { env: "Beasts & Wilderness", name: "Glass Snake", tier: "1", type: "Standard", diff: 14, atk: "+2", maxHp: 5, maxStress: 3, major: 6, severe: 10, weapon: "Glass Fangs", damageType: "Physical", dice: "1d8+2", motives: "climb, feed, keep distance, scare", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Armor-Shredding Shards</b>: On a successful attack within Melee range against the Snake, the attacker must mark an Armor Slot without receiving its benefits (they can still use armor to reduce the damage). If they can't mark an Armor Slot, they must mark an additional HP.", "<span class='cost-tag stress'>1 Stress</span> <b>Spinning Serpent</b>: Mark a Stress to make an attack against all targets within Very Close range. Targets the Snake succeeds against take 1d6+1 physical damage.", "<span class='cost-tag fear'>1 Fear</span> <b>Spitter</b>: Spend a Fear to introduce a d6 Spitter Die. When the Snake is in the spotlight, roll this die. On a result of 5 or higher, all targets in front of the Snake within Far range must succeed on an Agility Reaction Roll or take 1d4 physical damage. The Snake can take the spotlight a second time this GM turn."] },
  "green_ooze": { env: "Oozes", name: "Green Ooze", tier: "1", type: "Skulk", diff: 8, atk: "+1", maxHp: 5, maxStress: 2, major: 5, severe: 10, weapon: "Ooze Appendage", damageType: "Magic", dice: "1d6+1", motives: "camouflage, consume and multiply, creep up, envelop", experiences: "Camoufl age +3", features: ["<span class='cost-tag'>Passive</span> <b>Slow</b>: When you spotlight the Ooze and they don't have a token on their stat block, they can't act yet. Place a token on their stat block and describe what they're preparing to do. When you spotlight the Ooze and they have a token on their stat block, clear the token and they can act.", "<span class='cost-tag'>Passive</span> <b>Acidic Form</b>: When the Ooze makes a successful attack, the target must mark an Armor Slot without receiving its benefits (they can still use armor to reduce the damage). If they can't mark an Armor Slot, they must mark an additional HP.", "<span class='cost-tag stress'>2 Stress</span> <b>Envelop</b>: Make a standard attack against a target within Melee range. On a success, the Ooze envelops them and the target must mark 2 Stress. The target must mark an additional Stress when they make an action roll. If the Ooze takes Severe damage, the target is freed.", "<span class='cost-tag fear'>1 Fear</span> <b>Split</b>: When the Ooze has 3 or more HP marked, you can spend a Fear to split them into two Tiny Green Oozes (with no marked HP or Stress). Immediately spotlight both of them."] },
  "harrier": { env: "Social & Mercenaries", name: "Harrier", tier: "1", type: "Standard", diff: 12, atk: "+1", maxHp: 3, maxStress: 3, major: 5, severe: 9, weapon: "Javelin", damageType: "Physical", dice: "1d6+2", motives: "flank, harry, kite, profit", experiences: "Camouflage +2", features: ["<span class='cost-tag'>Passive</span> <b>Maintain Distance</b>: After making a standard attack, the Harrier can move anywhere within Far range.", "<span class='cost-tag stress'>1 Stress</span> <b>Fall Back</b>: When a creature moves into Melee range to make an attack, you can mark a Stress before the attack roll to move anywhere within Close range and make an attack against that creature. On a success, deal 1d10+2 physical damage."] },
  "head_guard": { env: "Settlement Guards", name: "Head Guard", tier: "1", type: "Leader", diff: 15, atk: "+4", maxHp: 7, maxStress: 3, major: 7, severe: 13, weapon: "Mace", damageType: "Physical", dice: "1d10+4", motives: "arrest, close gates, pin down, seek glory", experiences: "Commander +2, Local Knowledge +2", features: ["<span class='cost-tag fear'>2 Fear</span> <b>Rally Guards</b>: Spend 2 Fear to spotlight the Head Guard and up to 2d4 allies within Far range.", "<span class='cost-tag'>Passive</span> <b>On My Signal</b>: Countdown (5). When the Head Guard is in the spotlight for the first time, activate the countdown. It ticks down when a PC makes an attack roll. When it triggers, all Archer Guards within Far range make a standard attack with advantage against the nearest target within their range. If any attacks succeed on the same target, combine their damage.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Head Guard makes a successful attack against a PC, you gain a Fear."] },
  "jk_bandit": { env: "Jagged Knife", name: "Jagged Knife Bandit", tier: "1", type: "Standard", diff: 12, atk: "+1", maxHp: 5, maxStress: 3, major: 8, severe: 14, weapon: "Daggers", damageType: "Physical", dice: "1d8+1", motives: "escape, profit, steal, throw smoke", experiences: "Thief +2", features: ["<span class='cost-tag'>Passive</span> <b>Climber</b>: The Bandit climbs just as easily as they run.", "<span class='cost-tag'>Passive</span> <b>From Above</b>: When the Bandit succeeds on a standard attack from above a target, they deal 1d10+1 physical damage instead of their standard damage."] },
  "jk_hexer": { env: "Jagged Knife", name: "Jagged Knife Hexer", tier: "1", type: "Support", diff: 13, atk: "+2", maxHp: 4, maxStress: 4, major: 5, severe: 9, weapon: "Staff", damageType: "Magic", dice: "1d6+2", motives: "command, hex, profit", experiences: "Magical Knowledge +2", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Curse</b>: Choose a target within Far range and temporarily Curse them. While the target is Cursed, you can mark a Stress when that target rolls with Hope to make the roll be with Fear instead.", "<span class='cost-tag stress'>1 Stress</span> <b>Chaotic Flux</b>: Make an attack against up to three targets within Very Close range. Mark a Stress to deal 2d6+3 magic damage to targets the Hexer succeeded against."] },
  "jk_kneebreaker": { env: "Jagged Knife", name: "Jagged Knife Kneebreaker", tier: "1", type: "Bruiser", diff: 12, atk: "-3", maxHp: 7, maxStress: 4, major: 7, severe: 14, weapon: "Club", damageType: "Physical", dice: "1d4+6", motives: "grapple, intimidate, profit, steal", experiences: "Thief +2, Unveiled Threats +3", features: ["<span class='cost-tag'>Passive</span> <b>I've Got 'Em</b>: Creatures Restrained by the Kneebreaker take double damage from attacks by other adversaries.", "<span class='cost-tag'>Action</span> <b>Hold Them Down</b>: Make an attack against a target within Melee range. On a success, the target takes no damage but is Restrained and Vulnerable. The target can break free, clearing both conditions, with a successful Strength Roll or is freed automatically if the Kneebreaker takes Major or greater damage."] },
  "jk_lackey": { env: "Jagged Knife", name: "Jagged Knife Lackey", tier: "1", type: "Minion", diff: 9, atk: "-2", maxHp: 1, maxStress: 1, major: 0, severe: 0, weapon: "Daggers", damageType: "Physical", dice: "2", motives: "escape, profit, throw smoke", experiences: "Thief +2", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Lackey is defeated when they take any damage. For every 3 damage a PC deals to the Lackey, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Jagged Knife Lackeys within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 2 physical damage each. Combine this damage."] },
  "jk_lieutenant": { env: "Jagged Knife", name: "Jagged Knife Lieutenant", tier: "1", type: "Leader", diff: 13, atk: "+2", maxHp: 6, maxStress: 3, major: 7, severe: 14, weapon: "Javelin", damageType: "Physical", dice: "1d8+3", motives: "bully, command, profit, reinforce", experiences: "Local Knowledge +2", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Tactician</b>: When you spotlight the Lieutenant, mark a Stress to also spotlight two allies within Close range.", "<span class='cost-tag'>Passive</span> <b>More Where That Came From</b>: Summon three Jagged Knife Lackeys, who appear at Far range.", "<span class='cost-tag stress'>1 Stress</span> <b>Coup de Grace</b>: Spend a Fear to make an attack against a Vulnerable target within Close range. On a success, deal 2d6+12 physical damage and the target must mark a Stress.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Lieutenant makes a successful attack against a PC, you gain a Fear."] },
  "jk_shadow": { env: "Jagged Knife", name: "Jagged Knife Shadow", tier: "1", type: "Skulk", diff: 12, atk: "+1", maxHp: 3, maxStress: 3, major: 4, severe: 8, weapon: "Daggers", damageType: "Physical", dice: "1d4+4", motives: "ambush, conceal, divide, profit", experiences: "Intrusion +3", features: ["<span class='cost-tag'>Passive</span> <b>Backstab</b>: When the Shadow succeeds on a standard attack that has advantage, they deal 1d6+6 physical damage instead of their standard damage.", "<span class='cost-tag'>Passive</span> <b>Cloaked</b>: Become Hidden until after the Shadow's next attack. Attacks made while Hidden from this feature have advantage."] },
  "jk_sniper": { env: "Jagged Knife", name: "Jagged Knife Sniper", tier: "1", type: "Ranged", diff: 13, atk: "-1", maxHp: 3, maxStress: 2, major: 4, severe: 7, weapon: "Shortbow", damageType: "Physical", dice: "1d10+2", motives: "ambush, hide, profit, reposition", experiences: "Stealth +2", features: ["<span class='cost-tag'>Passive</span> <b>Unseen Strike</b>: If the Sniper is Hidden when they make a successful standard attack against a target, they deal 1d10+4 physical damage instead of their standard damage."] },
  "merchant": { env: "Social & Mercenaries", name: "Merchant", tier: "1", type: "Social", diff: 12, atk: "-4", maxHp: 3, maxStress: 3, major: 4, severe: 8, weapon: "Club", damageType: "Physical", dice: "1d4+1", motives: "buy low and sell high, create demand, inflate prices, seek profit", experiences: "Shrewd Negotiator +3", features: ["<span class='cost-tag'>Passive</span> <b>Preferential Treatment</b>: A PC who succeeds on a Presence Roll against the Merchant gains a discount on purchases. A PC who fails on a Presence Roll against the Merchant must pay more and has disadvantage on future Presence Rolls against the Merchant.", "<span class='cost-tag stress'>1 Stress</span> <b>The Runaround</b>: When a PC rolls a 14 or lower on a Presence Roll made against the Merchant, they must mark a Stress."] },
  "minor_chaos_elemental": { env: "Arcane Threats", name: "Minor Chaos Elemental", tier: "1", type: "Solo", diff: 14, atk: "+3", maxHp: 7, maxStress: 3, major: 7, severe: 14, weapon: "Warp Blast", damageType: "Magic", dice: "1d12+6", motives: "confound, destabilize, transmogrify", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Arcane Form</b>: The Elemental is resistant to magic damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Sickening Flux</b>: Mark a HP to force all targets within Close range to mark a Stress and become Vulnerable until their next rest or they clear a HP.", "<span class='cost-tag fear'>1 Fear</span> <b>Remake Reality</b>: Spend a Fear to transform the area within Very Close range into a different biome. All targets within this area take 2d6+3 direct magic damage.", "<span class='cost-tag'>Passive</span> <b>Magical Reflection</b>: When the Elemental takes damage from an attack within Close range, deal an amount of damage to the attacker equal to half the damage they dealt.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Elemental makes a successful attack against a PC, you gain a Fear."] },
  "minor_demon": { env: "Arcane Threats", name: "Minor Demon", tier: "1", type: "Solo", diff: 14, atk: "+3", maxHp: 8, maxStress: 4, major: 8, severe: 15, weapon: "Claws", damageType: "Physical", dice: "1d8+6", motives: "act erratically, corral targets, relish pain, torment", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Demon can be spotlighted up to two times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag'>Passive</span> <b>All Must Fall</b>: When a PC rolls a failure with Fear while within Close range of the Demon, they lose a Hope.", "<span class='cost-tag fear'>1 Fear</span> <b>Hellfire</b>: Spend a Fear to rain down hellfire within Far range. All targets within the area must make an Agility Reaction Roll. Targets who fail take 1d20+3 magic damage. Targets who succeed take half damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Reaper</b>: Before rolling damage for the Demon's attack, you can mark a Stress to gain a bonus to the damage roll equal to the Demon's current number of marked HP.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Demon makes a successful attack against a PC, you gain a Fear."] },
  "minor_fire_elemental": { env: "Arcane Threats", name: "Minor Fire Elemental", tier: "1", type: "Solo", diff: 13, atk: "+3", maxHp: 9, maxStress: 3, major: 7, severe: 15, weapon: "Elemental Blast", damageType: "Magic", dice: "1d10+4", motives: "encircle enemies, grow in size, intimidate, start fires", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Elemental can be spotlighted up to two times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag stress'>1 Stress</span> <b>Scorched Earth</b>: Mark a Stress to choose a point within Far range. The ground within Very Close range of that point immediately bursts into flames. All creatures within this area must make an Agility Reaction Roll. Targets who fail take 2d8 magic damage from the flames. Targets who succeed take half damage.", "<span class='cost-tag fear'>1 Fear</span> <b>Explosion</b>: Spend a Fear to erupt in a fiery explosion. Make an attack against all targets within Close range. Targets the Elemental succeeds against take 1d8 magic damage and are knocked back to Far range.", "<span class='cost-tag'>Passive</span> <b>Consume Kindling</b>: Three times per scene, when the Elemental moves onto objects that are highly flammable, consume them to clear a HP or a Stress.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Elemental makes a successful attack against a PC, you gain a Fear."] },
  "minor_treant": { env: "Forest & Fae", name: "Minor Treant", tier: "1", type: "Minion", diff: 10, atk: "-2", maxHp: 1, maxStress: 1, major: 0, severe: 0, weapon: "Clawed Branch", damageType: "Physical", dice: "4", motives: "crush, overwhelm, protect", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Treant is defeated when they take any damage. For every 5 damage a PC deals to the Treant, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Minor Treants within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 4 physical damage each. Combine this damage."] },
  "patchwork_zombie_hulk": { env: "Undead", name: "Patchwork Zombie Hulk", tier: "1", type: "Solo", diff: 13, atk: "+4", maxHp: 10, maxStress: 3, major: 8, severe: 15, weapon: "Too Many Arms", damageType: "Physical", dice: "1d20", motives: "absorb corpses, flail, hunger, terrify", experiences: "Intimidation +2, Tear Things Apart +2", features: ["<span class='cost-tag'>Passive</span> <b>Destructible</b>: When the Zombie takes Major or greater damage, they mark an additional HP.", "<span class='cost-tag'>Passive</span> <b>Flailing Limbs</b>: When the Zombie makes a standard attack, they can attack all targets within Very Close range.", "<span class='cost-tag'>Passive</span> <b>Another for the Pile</b>: When the Zombie is within Very Close range of a corpse, they can incorporate it into themselves, clearing a HP and a Stress.", "<span class='cost-tag stress'>1 Stress</span> <b>Tormented Screams</b>: Mark a Stress to cause all PCs within Far range to make a Presence Reaction Roll (13). Targets who fail lose a Hope and you gain a Fear for each. Targets who succeed must mark a Stress."] },
  "petty_noble": { env: "Social & Mercenaries", name: "Petty Noble", tier: "1", type: "Social", diff: 14, atk: "-3", maxHp: 3, maxStress: 5, major: 6, severe: 10, weapon: "Rapier", damageType: "Physical", dice: "1d6+1", motives: "abuse power, gather resources, mobilize minions", experiences: "Aristocrat +3", features: ["<span class='cost-tag'>Passive</span> <b>My Land, My Rules</b>: All social actions made against the Noble on their land have disadvantage.", "<span class='cost-tag stress'>1 Stress</span> <b>Guards, Seize Them!</b>: Once per scene, mark a Stress to summon 1d4 Bladed Guards, who appear at Far range to enforce the Noble's will.", "<span class='cost-tag fear'>1 Fear</span> <b>Exile</b>: Spend a Fear and target a PC. The Noble proclaims that the target and their allies are exiled from the noble's territory. While exiled, the target and their allies have disadvantage during social situations within the Noble's domain."] },
  "pirate_captain": { env: "Pirates", name: "Pirate Captain", tier: "1", type: "Leader", diff: 14, atk: "+4", maxHp: 7, maxStress: 5, major: 7, severe: 14, weapon: "Cutlass", damageType: "Physical", dice: "1d12+2", motives: "command, make 'em walk the plank, plunder, raid", experiences: "Commander +2, Sailor +3", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Swashbuckler</b>: When the Captain marks 2 or fewer HP from an attack within Melee range, the attacker must mark a Stress.", "<span class='cost-tag stress'>1 Stress</span> <b>Reinforcements</b>: Once per scene, mark a Stress to summon a Pirate Raiders Horde, which appears at Far range.", "<span class='cost-tag stress'>1 Stress</span> <b>No Quarter</b>: Spend a Fear to choose a target who has three or more Pirates within Melee range of them. The Captain leads the Pirates in hurling threats and promises of a watery grave. The target must make a Presence Reaction Roll. On a failure, the target marks 1d4+1 Stress. On a success, they must mark a Stress.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Captain makes a successful attack against a PC, you gain a Fear."] },
  "pirate_raiders": { env: "Pirates", name: "Pirate Raiders", tier: "1", type: "Horde", diff: 12, atk: "+1", maxHp: 4, maxStress: 3, major: 5, severe: 11, weapon: "Cutlass", damageType: "Physical", dice: "1d8+2", motives: "gang up, plunder, raid", experiences: "Sailor +3", features: ["<span class='cost-tag'>Passive</span> <b>Horde</b>: When the Raiders have marked half or more of their HP, their standard attack deals 1d4+1 physical damage instead.", "<span class='cost-tag stress'>1 Stress</span> <b>Swashbuckler</b>: When the Raiders mark 2 or fewer HP from an attack within Melee range, the attacker must mark a Stress."] },
  "pirate_tough": { env: "Pirates", name: "Pirate Tough", tier: "1", type: "Bruiser", diff: 13, atk: "+1", maxHp: 5, maxStress: 3, major: 8, severe: 15, weapon: "Massive Fists", damageType: "Physical", dice: "2d6", motives: "plunder, raid, smash, terrorize", experiences: "Sailor +2", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Swashbuckler</b>: When the Tough marks 2 or fewer HP from an attack within Melee range, the attacker must mark a Stress.", "<span class='cost-tag stress'>1 Stress</span> <b>Clear the Decks</b>: Make an attack against a target within Very Close range. On a success, mark a Stress to move into Melee range of the target, dealing 3d4 physical damage and knocking the target back to Close range."] },
  "red_ooze": { env: "Oozes", name: "Red Ooze", tier: "1", type: "Skulk", diff: 10, atk: "+1", maxHp: 5, maxStress: 3, major: 6, severe: 11, weapon: "Ooze Appendage", damageType: "Magic", dice: "1d8+3", motives: "camouflage, consume and multiply, ignite, start fires", experiences: "Camouflage +3", features: ["<span class='cost-tag'>Passive</span> <b>Creeping Fire</b>: The Ooze can only move within Very Close range as their normal movement. They light any flammable object they touch on fire.", "<span class='cost-tag'>Action</span> <b>Ignite</b>: Make an attack against a target within Very Close range. On a success, the target takes 1d8 magic damage and is Ignited until they're extinguished with a successful Finesse Roll (14). While Ignited, the target takes 1d4 magic damage when they make an action roll.", "<span class='cost-tag fear'>1 Fear</span> <b>Split</b>: When the Ooze has 3 or more HP marked, you can spend a Fear to split them into two Tiny Red Oozes (with no marked HP or Stress). Immediately spotlight both of them."] },
  "rotted_zombie": { env: "Undead", name: "Rotted Zombie", tier: "1", type: "Minion", diff: 8, atk: "-3", maxHp: 1, maxStress: 1, major: 0, severe: 0, weapon: "Bite", damageType: "Physical", dice: "2", motives: "eat flesh, hunger, maul, surround", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Zombie is defeated when they take any damage. For every 3 damage a PC deals to the Zombie, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Rotted Zombies within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 2 physical damage each. Combine this damage."] },
  "sellsword": { env: "Social & Mercenaries", name: "Sellsword", tier: "1", type: "Minion", diff: 10, atk: "+3", maxHp: 1, maxStress: 1, major: 0, severe: 0, weapon: "Longsword", damageType: "Physical", dice: "3", motives: "charge, lacerate, overwhelm, profit", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Sellsword is defeated when they take any damage. For every 4 damage a PC deals to the Sellsword, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Sellswords within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 3 physical damage each. Combine this damage."] },
  "shambling_zombie": { env: "Undead", name: "Shambling Zombie", tier: "1", type: "Standard", diff: 10, atk: "+0", maxHp: 4, maxStress: 1, major: 4, severe: 6, weapon: "Bite", damageType: "Physical", dice: "1d6+1", motives: "devour, hungry, mob enemy, shred flesh", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Too Many to Handle</b>: When the Zombie is within Melee range of a creature and at least one other Zombie is within Close range, all attacks against that creature have advantage.", "<span class='cost-tag stress'>1 Stress</span> <b>Horrifying</b>: Targets who mark HP from the Zombie's attacks must also mark a Stress."] },
  "skeleton_archer": { env: "Undead", name: "Skeleton Archer", tier: "1", type: "Ranged", diff: 9, atk: "+2", maxHp: 3, maxStress: 2, major: 4, severe: 7, weapon: "Shortbow", damageType: "Physical", dice: "1d8+1", motives: "perforate distracted targets, play dead, steal skin", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Opportunist</b>: When two or more adversaries are within Very Close range of a creature, all damage the Archer deals to that creature is doubled.", "<span class='cost-tag stress'>1 Stress</span> <b>Deadly Shot</b>: Make an attack against a Vulnerable target within Far range. On a success, mark a Stress to deal 3d4+8 physical damage."] },
  "skeleton_dredge": { env: "Undead", name: "Skeleton Dredge", tier: "1", type: "Minion", diff: 8, atk: "-1", maxHp: 1, maxStress: 1, major: 0, severe: 0, weapon: "Bone Claws", damageType: "Physical", dice: "1", motives: "fall apart, overwhelm, play dead, steal skin", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Dredge is defeated when they take any damage. For every 4 damage a PC deals to the Dredge, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Dredges within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 1 physical damage each. Combine this damage."] },
  "skeleton_knight": { env: "Undead", name: "Skeleton Knight", tier: "1", type: "Bruiser", diff: 13, atk: "+2", maxHp: 5, maxStress: 2, major: 7, severe: 13, weapon: "Rusty Greatsword", damageType: "Physical", dice: "1d10+2", motives: "cut down the living, steal skin, wreak havoc", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Terrifying</b>: When the Knight makes a successful attack, all PCs within Close range lose a Hope and you gain a Fear.", "<span class='cost-tag stress'>1 Stress</span> <b>Cut to the Bone</b>: Mark a Stress to make an attack against all targets within Very Close range. Targets the Knight succeeds against take 1d8+2 physical damage and must mark a Stress.", "<span class='cost-tag'>Action</span> <b>Dig Two Graves</b>: When the Knight is defeated, they make an attack against a target within Very Close range (prioritizing the creature who killed them). On a success, the target takes 1d4+8 physical damage and loses 1d4 Hope."] },
  "skeleton_warrior": { env: "Undead", name: "Skeleton Warrior", tier: "1", type: "Standard", diff: 10, atk: "+0", maxHp: 3, maxStress: 2, major: 4, severe: 8, weapon: "Sword", damageType: "Physical", dice: "1d6+2", motives: "feign death, gang up, steal skin", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Only Bones</b>: The Warrior is resistant to physical damage.", "<span class='cost-tag'>Passive</span> <b>Won't Stay Dead</b>: When the Warrior is defeated, you can spotlight them and roll a d6. On a result of 6, if there are other adversaries on the battlefield, the Warrior re-forms with no marked HP."] },
  "spellblade": { env: "Social & Mercenaries", name: "Spellblade", tier: "1", type: "Leader", diff: 14, atk: "+3", maxHp: 6, maxStress: 3, major: 8, severe: 14, weapon: "Empowered Longsword", damageType: "Physical/Magic", dice: "1d8+4", motives: "blast, command, endure", experiences: "Magical Knowledge +2", features: ["<span class='cost-tag'>Passive</span> <b>Arcane Steel</b>: Damage dealt by the Spellblade's standard attack is considered both physical and magic.", "<span class='cost-tag stress'>1 Stress</span> <b>Suppressing Blast</b>: Mark a Stress and target a group within Far range. All targets must succeed on an Agility Reaction Roll or take 1d8+2 magic damage. You gain a Fear for each target who marked HP from this attack.", "<span class='cost-tag fear'>2 Fear</span> <b>Move as a Unit</b>: Spend 2 Fear to spotlight up to five allies within Far range.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Spellblade makes a successful attack against a PC, you gain a Fear."] },
  "swarm_of_rats": { env: "Beasts & Wilderness", name: "Swarm of Rats", tier: "1", type: "Horde", diff: 10, atk: "-3", maxHp: 6, maxStress: 2, major: 6, severe: 10, weapon: "Claws", damageType: "Physical", dice: "1d8+2", motives: "consume, obscure, swarm", experiences: "", features: [] },
  "swarm_of_rats": { env: "Beasts & Wilderness", name: "Swarm Of Rats", tier: "1", type: "Horde", diff: 10, atk: "-3", maxHp: 6, maxStress: 2, major: 6, severe: 10, weapon: "Claws", damageType: "Physical", dice: "1d8+2", motives: "consume, obscure, swarm", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Horde</b>: When the Swarm has marked half or more of their HP, their standard attack deals 1d4+1 physical damage instead.", "<span class='cost-tag'>Passive</span> <b>In Your Face</b>: All targets within Melee range have disadvantage on attacks against targets other than the Swarm."] },
  "sylvan_soldier": { env: "Forest & Fae", name: "Sylvan Soldier", tier: "1", type: "Standard", diff: 11, atk: "+0", maxHp: 4, maxStress: 2, major: 6, severe: 11, weapon: "Scythe", damageType: "Physical", dice: "1d8+1", motives: "ambush, hide, overwhelm, protect, trail", experiences: "Tracker +2", features: ["<span class='cost-tag'>Passive</span> <b>Pack Tactics</b>: If the Soldier makes a standard attack and another Sylvan Soldier is within Melee range of the target, deal 1d8+5 physical damage instead of their standard damage.", "<span class='cost-tag fear'>1 Fear</span> <b>Forest Control</b>: Spend a Fear to pull down a tree within Close range. A creature hit by the tree must succeed on an Agility Reaction Roll (15) or take 1d10 physical damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Blend In</b>: When the Soldier makes a successful attack, you can mark a Stress to become Hidden until the Soldier's next attack or a PC succeeds on an Instinct Roll (14) to find them."] },
  "tangle_bramble": { env: "Forest & Fae", name: "Tangle Bramble", tier: "1", type: "Minion", diff: 11, atk: "-1", maxHp: 1, maxStress: 1, major: 0, severe: 0, weapon: "Thorns", damageType: "Physical", dice: "2", motives: "combine, drain, entangle", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Bramble is defeated when they take any damage. For every 4 damage a PC deals to the Tangle Bramble, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Tangle Brambles within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 2 physical damage each. Combine this damage.", "<span class='cost-tag'>Passive</span> <b>Drain and Multiply</b>: When an attack from the Bramble causes a target to mark HP and there are three or more Tangle Bramble Minions within Close range, you can combine the Minions into a Tangle Bramble Swarm Horde. The Horde's HP is equal to the number of Minions combined."] },
  "tangle_bramble_swarm": { env: "Forest & Fae", name: "Tangle Bramble Swarm", tier: "1", type: "Horde", diff: 12, atk: "+0", maxHp: 6, maxStress: 3, major: 6, severe: 11, weapon: "Thorns", damageType: "Physical", dice: "1d6+3", motives: "digest, entangle, immobilize", experiences: "Camouflage +2", features: ["<span class='cost-tag'>Passive</span> <b>Horde</b>: When the Swarm has marked half or more of their HP, their standard attack deals 1d4+2 physical damage instead.", "<span class='cost-tag stress'>1 Stress</span> <b>Crush</b>: Mark a Stress to deal 2d6+8 direct physical damage to a target with 3 or more bramble tokens.", "<span class='cost-tag'>Passive</span> <b>Encumber</b>: When the Swarm succeeds on an attack, give the target a bramble token. If a target has any bramble tokens, they are Restrained. If a target has 3 or more bramble tokens, they are also Vulnerable. All bramble tokens can be removed by succeeding on a Finesse Roll (12 + the number of bramble tokens) or dealing Major or greater damage to the Swarm. If bramble tokens are removed from a target using a Finesse Roll, a number of Tangle Bramble Minions spawn within Melee range equal to the number of tokens removed."] },
  "tiny_green_ooze": { env: "Oozes", name: "Tiny Green Ooze", tier: "1", type: "Skulk", diff: 14, atk: "-1", maxHp: 2, maxStress: 1, major: 0, severe: 0, weapon: "Ooze Appendage", damageType: "Magic", dice: "1d4+1", motives: "camouflage, creep up", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Acidic Form</b>: When the Ooze makes a successful attack, the target must mark an Armor Slot without receiving its benefits (they can still use armor to reduce the damage). If they can't mark an Armor Slot, they must mark an additional HP."] },
  "tiny_red_ooze": { env: "Oozes", name: "Tiny Red Ooze", tier: "1", type: "Skulk", diff: 11, atk: "-1", maxHp: 2, maxStress: 1, major: 0, severe: 0, weapon: "Ooze Appendage", damageType: "Magic", dice: "1d4+2", motives: "blaze, camouflage", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Burning</b>: When a creature within Melee range deals damage to the Ooze, they take 1d6 direct magic damage."] },
  "weaponmaster": { env: "Social & Mercenaries", name: "Weaponmaster", tier: "1", type: "Bruiser", diff: 14, atk: "+2", maxHp: 6, maxStress: 3, major: 8, severe: 15, weapon: "Claymore", damageType: "Physical", dice: "1d12+2", motives: "act first, aim for the weakest, intimidate", experiences: "", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Goading Strike</b>: Make a standard attack against a target. On a success, mark a Stress to Taunt the target until their next successful attack. The next time the Taunted target attacks, they have disadvantage against targets other than the Weaponmaster.", "<span class='cost-tag fear'>1 Fear</span> <b>Adrenaline Burst</b>: Once per scene, spend a Fear to clear 2 HP and 2 Stress.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Weaponmaster makes a successful attack against a PC, you gain a Fear."] },
  "young_dryad": { env: "Forest & Fae", name: "Young Dryad", tier: "1", type: "Leader", diff: 11, atk: "+0", maxHp: 6, maxStress: 2, major: 6, severe: 11, weapon: "Scythe", damageType: "Physical", dice: "1d8+5", motives: "command, nurture, prune the unwelcome", experiences: "Leadership +3", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Voice of the Forest</b>: Mark a Stress to spotlight 1d4 allies within range of a target they can attack without moving. On a success, their attacks deal half damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Thorny Cage</b>: Spend a Fear to form a cage around a target within Very Close range and Restrain them until they're freed with a successful Strength Roll. When a creature makes an action roll against the cage, they must mark a Stress.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Dryad makes a successful attack against a PC, you gain a Fear."] },
  "zombie_pack": { env: "Undead", name: "Zombie Pack", tier: "1", type: "Horde", diff: 8, atk: "-1", maxHp: 6, maxStress: 3, major: 6, severe: 12, weapon: "Bite", damageType: "Physical", dice: "1d10+2", motives: "consume flesh, hunger, maul", experiences: "", features: [] },
  "apprentice_assassin": { env: "Criminal Underworld", name: "Apprentice Assassin", tier: "2", type: "Minion", diff: 13, atk: "-1", maxHp: 1, maxStress: 1, major: 0, severe: 0, weapon: "Thrown Dagger", damageType: "Physical", dice: "4", motives: "act reckless, kill, prove their worth, show off", experiences: "Intrusion +2", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Assassin is defeated when they take any damage. For every 6 damage a PC deals to the Assassin, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Apprentice Assassins within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 4 physical damage each. Combine this damage."] },
  "archer_squadron": { env: "Social & Mercenaries", name: "Archer Squadron", tier: "2", type: "Horde", diff: 13, atk: "+0", maxHp: 4, maxStress: 3, major: 8, severe: 16, weapon: "Longbow", damageType: "Physical", dice: "2d6+3", motives: "stick together, survive, volley fire", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Horde</b>: When the Squadron has marked half or more of their HP, their standard attack deals 1d6+3 physical damage instead.", "<span class='cost-tag fear'>1 Fear</span> <b>Focused Volley</b>: Spend a Fear to target a point within Far range. Make an attack with advantage against all targets within Close range of that point. Targets the Squadron succeeds against take 1d10+4 physical damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Suppressing Fire</b>: Mark a Stress to target a point within Far range. Until the next roll with Fear, a creature who moves within Close range of that point must make an Agility Reaction Roll. On a failure, they take 2d6+3 physical damage. On a success, they take half damage."] },
  "assassin_poisoner": { env: "Criminal Underworld", name: "Assassin Poisoner", tier: "2", type: "Skulk", diff: 14, atk: "+3", maxHp: 4, maxStress: 4, major: 8, severe: 16, weapon: "Poisoned Throwing Dagger", damageType: "Physical", dice: "2d8+1", motives: "anticipate, get paid, kill, taint food and water", experiences: "Intrusion +2", features: ["<span class='cost-tag'>Passive</span> <b>Grindletooth Venom</b>: Targets who mark HP from the Assassin's attacks are Vulnerable until they clear a HP.", "<span class='cost-tag'>Passive</span> <b>Out of Nowhere</b>: The Assassin has advantage on attacks if they are Hidden.", "<span class='cost-tag'>Passive</span> <b>Fumigation</b>: Drop a smoke bomb that fi lls the air within Close range with smoke, Dizzying all targets in this area. Dizzied targets have disadvantage on their next action roll, then clear the condition."] },
  "battle_box": { env: "Arcane Threats", name: "Battle Box", tier: "2", type: "Solo", diff: 15, atk: "+2", maxHp: 8, maxStress: 6, major: 10, severe: 20, weapon: "Slam", damageType: "Physical", dice: "2d6+3", motives: "change tactics, trample foes, wait in disguise", experiences: "Camouflage +2", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Box can be spotlighted up to two times times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag stress'>1 Stress</span> <b>Randomized Tactics</b>: Mark a Stress and roll a d6. The Box uses the corresponding move: 1. Mana Beam. The Box fires a searing beam. Make an attack against a target within Far range. On a success, deal 2d10+2 magic damage. 2. Fire Jets. The Box shoots into the air, spinning and releasing jets of flame. Make an attack against all targets within Close range. Targets the Box succeeds against take 2d8 physical damage. 3. Trample. The Box rockets around erratically. Make an attack against all PCs within Close range. Targets the Box succeeds against take 1d6+5 physical damage and are Vulnerable until their next roll with Hope. 4. Shocking Gas. The Box sprays out a silver gas sparking with lightning. All targets within Close range must succeed on a Finesse Reaction Roll or mark 3 Stress. 5. Stunning Clap. The Box leaps and their sides clap, creating a small sonic boom. All targets within Very Close range must succeed on a Strength Reaction Roll or become Vulnerable until the cube is defeated. 6. Psionic Whine. The Box releases a cluster of mechanical bees whose buzz rattles mortal minds. All targets within Close range must succeed on a Presence Reaction Roll or take 2d4+9 direct magic damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Overcharge</b>: Before rolling damage for the Box's attack, you can mark a Stress to add a d6 to the damage roll. Additionally, you gain a Fear.", "<span class='cost-tag'>Passive</span> <b>Death Quake</b>: When the Box marks their last HP, the magic powering them ruptures in an explosion of force. All targets within Close range must succeed on an Instinct Reaction Roll or take 2d8+1 magic damage."] },
  "chaos_skull": { env: "Arcane Threats", name: "Chaos Skull", tier: "2", type: "Ranged", diff: 15, atk: "+2", maxHp: 5, maxStress: 4, major: 8, severe: 16, weapon: "Energy Blast", damageType: "Magic", dice: "2d8+3", motives: "cackle, consume magic, serve creator", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Levitation</b>: The Skull levitates several feet off the ground and can't be Restrained.", "<span class='cost-tag'>Passive</span> <b>Wards</b>: The Skull is resistant to magic damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Magic Burst</b>: Mark a Stress to make an attack against all targets within Close range. Targets the Skull succeeds against take 2d6+4 magic damage.", "<span class='cost-tag fear'>1 Fear</span> <b>Siphon Magic</b>: Spend a Fear to make an attack against a PC with a Spellcast trait within Very Close range. On a success, the target marks 1d4 Stress and the Skull clears that many Stress. Additionally, on a success, the Skull can immediately be spotlighted again."] },
  "conscript": { env: "Social & Mercenaries", name: "Conscript", tier: "2", type: "Minion", diff: 12, atk: "+0", maxHp: 1, maxStress: 1, major: 0, severe: 0, weapon: "Spears", damageType: "Physical", dice: "6", motives: "follow orders, gang up, survive", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Conscript is defeated when they take any damage. For every 6 damage a PC deals to the Conscript, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Conscripts within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 6 physical damage each. Combine this damage."] },
  "courtesan": { env: "Nobility & Court", name: "Courtesan", tier: "2", type: "Social", diff: 13, atk: "-3", maxHp: 3, maxStress: 4, major: 7, severe: 13, weapon: "Dagger", damageType: "Physical", dice: "1d4+3", motives: "entice, maneuver, secure patrons", experiences: "Manipulation +3, Socialite +3", features: ["<span class='cost-tag stress'>2 Stress</span> <b>Searing Glance</b>: When a PC within Close range makes a Presence Roll, you can mark a Stress to cast a gaze toward the aftermath. On the target's failure, they must mark 2 Stress and are Vulnerable until the scene ends or they succeed on a social action against the Courtesan. On the target's success, they must mark a Stress."] },
  "cult_adept": { env: "Cult", name: "Cult Adept", tier: "2", type: "Support", diff: 14, atk: "+2", maxHp: 4, maxStress: 6, major: 9, severe: 18, weapon: "Rune-Covered Rod", damageType: "Magic", dice: "2d4+3", motives: "curry favor, hinder foes, uncover knowledge", experiences: "Fallen Lore +2, Rituals +2", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Enervating Blast</b>: Spend a Fear to make a standard attack against a target within range. On a success, the target must mark a Stress.", "<span class='cost-tag stress'>1 Stress</span> <b>Shroud of the Fallen</b>: Mark a Stress to wrap an ally within Close range in a shroud of Protection until the Adept marks their last HP. While Protected, the target has resistance to all damage.", "<span class='cost-tag fear'>1 Fear</span> <b>Shadow Shackles</b>: Spend a Fear and choose a point within Far range. All targets within Close range of that point are Restrained in smoky chains until they break free with a successful Strength or Instinct Roll. A target Restrained by this feature must spend a Hope to make an action roll.", "<span class='cost-tag'>Passive</span> <b>Fear Is Fuel</b>: Twice per scene, when a PC rolls a failure with Fear, clear a Stress."] },
  "cult_fang": { env: "Cult", name: "Cult Fang", tier: "2", type: "Skulk", diff: 15, atk: "+2", maxHp: 4, maxStress: 4, major: 9, severe: 17, weapon: "Long Knife", damageType: "Physical", dice: "2d8+4", motives: "capture sacrifi ces, isolate prey, rise in the ranks", experiences: "", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Shadow's Embrace</b>: The Fang can climb and walk on vertical surfaces. Mark a Stress to move from one shadow to another within Far range.", "<span class='cost-tag stress'>2 Stress</span> <b>Pick Off the Straggler</b>: Mark a Stress to cause a target within Melee range to make an Instinct Reaction Roll. On a failure, the target must mark 2 Stress and is teleported with the Fang to a shadow within Far range, making them temporarily Vulnerable. On a success, the target must mark a Stress."] },
  "cult_initiate": { env: "Cult", name: "Cult Initiate", tier: "2", type: "Minion", diff: 13, atk: "+0", maxHp: 1, maxStress: 1, major: 0, severe: 0, weapon: "Ritual Dagger", damageType: "Physical", dice: "5", motives: "follow orders, gain power, seek forbidden knowledge", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Initiate is defeated when they take any damage. For every 6 damage a PC deals to the Initiate, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Cult Initiates within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 5 physical damage each. Combine this damage."] },
  "demonic_hound_pack": { env: "Demons", name: "Demonic Hound Pack", tier: "2", type: "Horde", diff: 15, atk: "+0", maxHp: 6, maxStress: 3, major: 11, severe: 23, weapon: "Claws and Fangs", damageType: "Physical", dice: "2d8+2", motives: "cause fear, consume flesh, please masters", experiences: "Scent Tracking +3", features: ["<span class='cost-tag'>Passive</span> <b>Horde</b>: When the Pack has marked half or more of their HP, their standard attack deals 2d4+1 physical damage instead.", "<span class='cost-tag stress'>2 Stress</span> <b>Dreadhowl</b>: Mark a Stress to make all targets within Very Close range lose a Hope. If a target is not able to lose a Hope, they must instead mark 2 Stress.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Pack makes a successful attack against a PC, you gain a Fear."] },
  "electric_eels": { env: "Beasts & Solos", name: "Electric Eels", tier: "2", type: "Horde", diff: 14, atk: "+0", maxHp: 5, maxStress: 3, major: 10, severe: 20, weapon: "Shocking Bite", damageType: "Physical", dice: "2d6+4", motives: "avoid larger predators, shock prey, tear apart", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Horde</b>: When the Eels have marked half or more of their HP, their standard attack deals 2d4+1 physical damage instead.", "<span class='cost-tag stress'>1 Stress</span> <b>Paralyzing Shock</b>: Mark a Stress to make a standard attack against all targets within Very Close range. You gain a Fear for each target that marks HP."] },
  "elite_soldier": { env: "Social & Mercenaries", name: "Elite Soldier", tier: "2", type: "Standard", diff: 15, atk: "+1", maxHp: 4, maxStress: 3, major: 9, severe: 18, weapon: "Spear", damageType: "Physical", dice: "2d8+4", motives: "gain glory, keep order, make alliances", experiences: "", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Reinforce</b>: Mark a Stress to move into Melee range of an ally and make a standard attack against a target within Very Close range. On a success, deal 2d10+2 physical damage and the ally can clear a Stress.", "<span class='cost-tag stress'>1 Stress</span> <b>Vassal's Loyalty</b>: When the Soldier is within Very Close range of a knight or other noble who would take damage, you can mark a Stress to move into Melee range of them and take the damage instead."] },
  "failed_experiment": { env: "Arcane Threats", name: "Failed Experiment", tier: "2", type: "Standard", diff: 13, atk: "+1", maxHp: 3, maxStress: 3, major: 12, severe: 23, weapon: "Bite and Claw", damageType: "Physical", dice: "2d6+5", motives: "devour, hunt, track", experiences: "Copycat +3", features: ["<span class='cost-tag'>Passive</span> <b>Warped Fortitude</b>: The Experiment is resistant to physical damage.", "<span class='cost-tag'>Passive</span> <b>Overwhelm</b>: When a target the Experiment attacks has other adversaries within Very Close range, the Experiment deals double damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Lurching Lunge</b>: Mark a Stress to spotlight the Experiment as an additional GM move instead of spending Fear."] },
  "giant_beastmaster": { env: "Giants", name: "Giant Beastmaster", tier: "2", type: "Leader", diff: 16, atk: "+2", maxHp: 6, maxStress: 5, major: 12, severe: 24, weapon: "Longbow", damageType: "Physical", dice: "2d8+4", motives: "command, make a living, maneuver, pin down, protect companion animals", experiences: "Animal Handling +3", features: ["<span class='cost-tag'>Passive</span> <b>Two as One</b>: When the Beastmaster is spotlighted, you can also spotlight a Tier 1 animal adversary currently under their control.", "<span class='cost-tag stress'>1 Stress</span> <b>Pinning Strike</b>: Make a standard attack against a target. On a success, you can mark a Stress to pin them to a nearby surface. The pinned target is Restrained until they break free with a successful Finesse or Strength Roll.", "<span class='cost-tag'>Passive</span> <b>Deadly Companion</b>: Twice per scene, summon a Bear, Dire Wolf, or similar Tier 1 animal adversary under the Beastmaster's control. The adversary appears at Close range and is immediately spotlighted."] },
  "giant_brawler": { env: "Giants", name: "Giant Brawler", tier: "2", type: "Bruiser", diff: 15, atk: "+2", maxHp: 7, maxStress: 4, major: 14, severe: 28, weapon: "Warhammer", damageType: "Physical", dice: "2d12+3", motives: "make a living, overwhelm, slam, topple", experiences: "Intrusion +2", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Battering Ram</b>: Mark a Stress to have the Brawler charge at an inanimate object within Close range they could feasibly smash (such as a wall, cart, or market stand) and destroy it. All targets within Very Close range of the object must succeed on an Agility Reaction Roll or take 2d4+3 physical damage from the shrapnel.", "<span class='cost-tag'>Passive</span> <b>Bloody Reprisal</b>: When the Brawler marks 2 or more HP from an attack within Very Close range, you can make a standard attack against the attacker. On a success, the Brawler deals 2d6+15 physical damage instead of their standard damage.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Brawler makes a successful attack against a PC, you gain a Fear."] },
  "giant_eagle": { env: "Giants", name: "Giant Eagle", tier: "2", type: "Skulk", diff: 14, atk: "+1", maxHp: 4, maxStress: 4, major: 8, severe: 19, weapon: "Claws and Beak", damageType: "Physical", dice: "2d6+3", motives: "hunt prey, stay mobile, strike decisively", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Flight</b>: While flying, the Eagle gains a +3 bonus to their Difficulty.", "<span class='cost-tag stress'>1 Stress</span> <b>Deadly Dive</b>: Mark a Stress to attack a target within Far range. On a success, deal 2d10+2 physical damage and knock the target over, making them Vulnerable until they next act.", "<span class='cost-tag'>Action</span> <b>Take Off</b>: Make an attack against a target within Very Close range. On a success, deal 2d4+3 physical damage and the target must succeed on an Agility Reaction Roll or become temporarily Restrained within the Eagle's massive talons. If the target is Restrained, the Eagle immediately lifts into the air to Very Far range above the battlefield while holding them.", "<span class='cost-tag'>Passive</span> <b>Deadly Drop</b>: While flying, the Eagle can drop a Restrained target they are holding. When dropped, the target is no longer Restrained but starts falling. If their fall isn't prevented during the PCs' next action, the target takes 2d20 physical damage when they land."] },
  "giant_recruit": { env: "Giants", name: "Giant Recruit", tier: "2", type: "Minion", diff: 13, atk: "+1", maxHp: 1, maxStress: 2, major: 0, severe: 0, weapon: "Warhammer", damageType: "Physical", dice: "5", motives: "batter, make a living, overwhelm, terrify", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Recruit is defeated when they take any damage. For every 7 damage a PC deals to the Recruit, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Giant Recruits within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 5 physical damage each. Combine this damage."] },
  "gorgon": { env: "Beasts & Solos", name: "Gorgon", tier: "2", type: "Solo", diff: 15, atk: "+4", maxHp: 9, maxStress: 3, major: 13, severe: 25, weapon: "Sunsear Shortbow", damageType: "Magic", dice: "2d20+3", motives: "corner, hit-and-run, petrify, seek vengeance", experiences: "Stealth +3", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Gorgon can be spotlighted up to two times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag'>Passive</span> <b>Sunsear Arrows</b>: When the Gorgon makes a successful standard attack, the target Glows until the end of the scene and can't become Hidden. Attack rolls made against a Glowing target have advantage.", "<span class='cost-tag stress'>1 Stress</span> <b>Crown of Serpents</b>: Make an attack roll against a target within Melee range using the Gorgon's protective snakes. On a success, mark a Stress to deal 2d10+4 physical damage and the target must mark a Stress.", "<span class='cost-tag fear'>1 Fear</span> <b>Petrifying Gaze</b>: When the Gorgon takes damage from an attack within Close range, you can spend a Fear to force the attacker to make an Instinct Reaction Roll. On a failure, they begin to turn to stone, marking a HP and starting a Petrifi cation Countdown (4). This countdown ticks down when the Gorgon is attacked. When it triggers, the target must make a death move. If the Gorgon is defeated, all petrifi cation countdowns end.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Gorgon makes a successful attack against a PC, you gain a Fear."] },
  "juvenile_flickerfly": { env: "Beasts & Solos", name: "Juvenile Flickerfly", tier: "2", type: "Solo", diff: 14, atk: "+3", maxHp: 10, maxStress: 5, major: 13, severe: 26, weapon: "Wing Slash", damageType: "Physical", dice: "2d10+4", motives: "collect shiny things, hunt, swoop", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Flickerfly can be spotlighted up to three times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag'>Passive</span> <b>Peerless Accuracy</b>: Before the Flickerfly makes an attack, roll a d6. On a result of 4 or higher, the target's Evasion is halved against this attack.", "<span class='cost-tag stress'>1 Stress</span> <b>Mind Dance</b>: Mark a Stress to create a magically dazzling display that grapples the minds of nearby foes. All targets within Close range must make an Instinct Reaction Roll. For each target who failed, you gain a Fear and the Flickerfly learns one of the target's fears.", "<span class='cost-tag stress'>1 Stress</span> <b>Hallucinatory Breath</b>: Countdown (Loop 1d6). When the Flickerfly takes damage for the first time, activate the countdown. When it triggers, the Flickerfly breathes hallucinatory gas on all targets in front of them up to Far range. Targets must succeed on an Instinct Reaction Roll or be tormented by fearful hallucinations. Targets whose fears are known to the Flickerfly have disadvantage on this roll. Targets who fail must mark a Stress and lose a Hope."] },
  "knight_of_the_realm": { env: "Nobility & Court", name: "Knight Of The Realm", tier: "2", type: "Leader", diff: 15, atk: "+4", maxHp: 6, maxStress: 4, major: 13, severe: 26, weapon: "Longsword", damageType: "Physical", dice: "2d10+4", motives: "run down, seek glory, show dominance", experiences: "Ancient Knowledge +3, High Society +2, Tactics +2", features: ["<span class='cost-tag'>Passive</span> <b>Chevalier</b>: While the Knight is on a mount, they gain a +2 bonus to their Difficulty. When they take Severe damage, they're knocked from their mount and lose this benefi t until they're next spotlighted.", "<span class='cost-tag'>Passive</span> <b>Heavily Armored</b>: When the Knight takes physical damage, reduce it by 3.", "<span class='cost-tag stress'>1 Stress</span> <b>Cavalry Charge</b>: If the Knight is mounted, move up to Far range and make a standard attack against a target. On a success, deal 2d8+4 physical damage and the target must mark a Stress.", "<span class='cost-tag stress'>1 Stress</span> <b>For the Realm!</b>: Mark a Stress to spotlight 1d4+1 allies. Attacks they make while spotlighted in this way deal half damage."] },
  "masked_thief": { env: "Criminal Underworld", name: "Masked Thief", tier: "2", type: "Skulk", diff: 14, atk: "+3", maxHp: 4, maxStress: 5, major: 8, severe: 17, weapon: "Backsword", damageType: "Physical", dice: "2d8+3", motives: "evade, hide, pilfer, profit", experiences: "Acrobatics +3", features: ["<span class='cost-tag'>Action</span> <b>Quick Hands</b>: Make an attack against a target within Melee range. On a success, deal 1d8+2 physical damage and the Thief steals one item or consumable from the target's inventory.", "<span class='cost-tag stress'>1 Stress</span> <b>Escape Plan</b>: Mark a Stress to reveal a snare trap set anywhere on the battlefield by the Thief. All targets within Very Close range of the trap must succeed on an Agility Reaction Roll (13) or be pulled off their feet and suspended upside down. A target is Restrained and Vulnerable until they break free, ending both conditions, with a successful Finesse or Strength Roll (13)."] },
  "master_assassin": { env: "Criminal Underworld", name: "Master Assassin", tier: "2", type: "Leader", diff: 15, atk: "+5", maxHp: 7, maxStress: 5, major: 12, severe: 25, weapon: "Serrated Dagger", damageType: "Physical", dice: "2d10+2", motives: "ambush, get out alive, kill, prepare for all scenarios", experiences: "Command +3, Intrusion +3", features: ["<span class='cost-tag'>Passive</span> <b>Won't See It Coming</b>: The Assassin deals direct damage while they're Hidden.", "<span class='cost-tag stress'>1 Stress</span> <b>Strike as One</b>: Mark a Stress to spotlight a number of other Assassins equal to the Assassin's unmarked Stress.", "<span class='cost-tag fear'>1 Fear</span> <b>The Subtle Blade</b>: When the Assassin successfully makes a standard attack against a Vulnerable target, you can spend a Fear to deal Severe damage instead of their standard damage.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Assassin makes a successful attack against a PC, you gain a Fear."] },
  "merchant_baron": { env: "Nobility & Court", name: "Merchant Baron", tier: "2", type: "Social", diff: 15, atk: "-2", maxHp: 5, maxStress: 3, major: 9, severe: 19, weapon: "Rapier", damageType: "Physical", dice: "1d6+2", motives: "abuse power, gather resources, mobilize minions", experiences: "Nobility +2, Trade +2", features: ["<span class='cost-tag stress'>2 Stress</span> <b>Everyone Has a Price</b>: Spend a Fear to off er a target a dangerous bargain for something they want or need. If used on a PC, they must make a Presence Reaction Roll (17). On a failure, they must mark 2 Stress or take the deal.", "<span class='cost-tag stress'>1 Stress</span> <b>The Best Muscle Money Can Buy</b>: Once per scene, mark a Stress to summon 1d4+1 Tier 1 adversaries, who appear at Far range, to enforce the Baron's will."] },
  "minotaur_wrecker": { env: "Giants", name: "Minotaur Wrecker", tier: "2", type: "Bruiser", diff: 16, atk: "+2", maxHp: 7, maxStress: 5, major: 14, severe: 27, weapon: "Battleaxe", damageType: "Physical", dice: "2d8+5", motives: "consume, gore, navigate, overpower, pursue", experiences: "Navigation +2", features: ["<span class='cost-tag fear'>1 Fear</span> <b>Ramp Up</b>: You must spend a Fear to spotlight the Minotaur. While spotlighted, they can make their standard attack against all targets within range.", "<span class='cost-tag stress'>1 Stress</span> <b>Charging Bull</b>: Mark a Stress to charge through a group within Close range and make an attack against all targets in the Minotaur's path. Targets the Minotaur succeeds against take 2d6+8 physical damage and are knocked back to Very Far range. If a target is knocked into a solid object or another creature, they take an extra 1d6 damage (combine the damage).", "<span class='cost-tag'>Action</span> <b>Gore</b>: Make an attack against a target within Very Close range, moving the Minotaur into Melee range of them. On a success, deal 2d8 direct physical damage."] },
  "mortal_hunter": { env: "Hunters", name: "Mortal Hunter", tier: "2", type: "Leader", diff: 16, atk: "+5", maxHp: 6, maxStress: 4, major: 15, severe: 27, weapon: "Tear at Flesh", damageType: "Physical", dice: "2d12+1", motives: "devour, hunt, track", experiences: "Bloodhound +3", features: ["<span class='cost-tag'>Passive</span> <b>Terrifying</b>: When the Hunter makes a successful attack, all PCs within Far range lose a Hope and you gain a Fear.", "<span class='cost-tag fear'>1 Fear</span> <b>Deathlock</b>: Spend a Fear to curse a target within Very Close range with a necrotic Deathlock until the end of the scene. Attacks made by the Hunter against a Deathlocked target deal direct damage. The Hunter can only maintain one Deathlock at a time.", "<span class='cost-tag stress'>1 Stress</span> <b>Inevitable Death</b>: Mark a Stress to spotlight 1d4 allies. Attacks they make while spotlighted in this way deal half damage.", "<span class='cost-tag'>Action</span> <b>Rampage</b>: Countdown (Loop 1d6). When the Hunter is in the spotlight for the first time, activate the countdown. When it triggers, move the Hunter in a straight line to a point within Far range and make an attack against all targets in their path. Targets the Hunter succeeds against take 2d8+2 physical damage."] },
  "royal_advisor": { env: "Nobility & Court", name: "Royal Advisor", tier: "2", type: "Social", diff: 14, atk: "-3", maxHp: 3, maxStress: 3, major: 8, severe: 15, weapon: "Wand", damageType: "Physical", dice: "1d4+3", motives: "curry favor, manufacture evidence, scheme", experiences: "Administration +3, Courtier +3", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Devastating Retort</b>: A PC who rolls less than 17 on an action roll targeting the Advisor must mark a Stress.", "<span class='cost-tag stress'>1 Stress</span> <b>Bend Ears</b>: Mark a Stress to infl uence an NPC within Melee range with whispered words. That target's opinion on one matter shifts toward the Advisor's preference unless it is in direct opposition to the target's motives.", "<span class='cost-tag fear'>1 Fear</span> <b>Scapegoat</b>: Spend a Fear to convince a crowd or notable individual that one person or group is responsible for some problem facing the target. The target becomes hostile to the scapegoat until convinced of their innocence with a successful Presence Roll (17)."] },
  "secret_keeper": { env: "Cult", name: "Secret-keeper", tier: "2", type: "Leader", diff: 16, atk: "+3", maxHp: 7, maxStress: 4, major: 13, severe: 26, weapon: "Sigil-laden Staff", damageType: "Magic", dice: "2d12", motives: "amass great power, plot, take command", experiences: "Coercion +2, Fallen Lore +2", features: ["<span class='cost-tag fear'>2 Fear</span> <b>Seize Your Moment</b>: Spend 2 Fear to spotlight 1d4 allies. Attacks they make while spotlighted in this way deal half damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Our Master's Will</b>: When you spotlight an ally within Far range, mark a Stress to gain a Fear.", "<span class='cost-tag'>Passive</span> <b>Summoning Ritual</b>: Countdown (6). When the Secret-Keeper is in the spotlight for the first time, activate the countdown. When they mark HP, tick down this countdown by the number of HP marked. When it triggers, summon a Minor Demon who appears at Close range.", "<span class='cost-tag stress'>1 Stress</span> <b>Fallen Hounds</b>: Once per scene, when the Secret- Keeper marks 2 or more HP, you can mark a Stress to summon a Demonic Hound Pack, which appears at Close range and is immediately spotlighted."] },
  "shark": { env: "Beasts & Solos", name: "Shark", tier: "2", type: "Bruiser", diff: 14, atk: "+2", maxHp: 7, maxStress: 3, major: 14, severe: 28, weapon: "Toothy Maw", damageType: "Physical", dice: "2d12+1", motives: "find the blood, isolate prey, target the weak", experiences: "Sense of Smell +3", features: ["<span class='cost-tag'>Passive</span> <b>Terrifying</b>: When the Shark makes a successful attack, all PCs within Far range lose a Hope and you gain a Fear.", "<span class='cost-tag'>Passive</span> <b>Rending Bite</b>: When the Shark makes a successful attack, the target must mark an Armor Slot without receiving its benefits (they can still use armor to reduce the damage). If they can't mark an Armor Slot, they must mark an additional HP.", "<span class='cost-tag stress'>1 Stress</span> <b>Blood in the Water</b>: When a creature within Close range of the Shark marks HP from another creature's attack, you can mark a Stress to immediately spotlight the Shark, moving them into Melee range of the target and making a standard attack."] },
  "siren": { env: "Mythic Sea", name: "Siren", tier: "2", type: "Skulk", diff: 14, atk: "+2", maxHp: 5, maxStress: 3, major: 9, severe: 18, weapon: "Distended Jaw Bite", damageType: "Physical", dice: "2d6+3", motives: "consume, lure prey, subdue with song", experiences: "Song Repertoire +3", features: ["<span class='cost-tag'>Passive</span> <b>Captive Audience</b>: If the Siren makes a standard attack against a target Entranced by their song, the attack deals 2d10+1 damage instead of their standard damage.", "<span class='cost-tag stress'>2 Stress</span> <b>Enchanting Song</b>: Spend a Fear to sing a song that affects all targets within Close range. Targets must succeed on an Instinct Reaction Roll or become Entranced until they mark 2 Stress. Other Sirens within Close range of the target can mark a Stress to each add a +1 bonus to the Difficulty of the reaction roll. While Entranced, a target can't act and is Vulnerable."] },
  "spectral_archer": { env: "Undead", name: "Spectral Archer", tier: "2", type: "Ranged", diff: 13, atk: "+3", maxHp: 3, maxStress: 3, major: 6, severe: 14, weapon: "Longbow", damageType: "Physical", dice: "2d10+2", motives: "move through solid objects, stay out of the fray, rehash old battles", experiences: "Ancient Knowledge +2", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Ghost</b>: The Archer has resistance to physical damage. Mark a Stress to move up to Close range through solid objects.", "<span class='cost-tag fear'>1 Fear</span> <b>Pick Your Target</b>: Spend a Fear to make an attack within Far range against a PC who is within Very Close range of at least two other PCs. On a success, the target takes 2d8+12 physical damage."] },
  "spectral_captain": { env: "Undead", name: "Spectral Captain", tier: "2", type: "Leader", diff: 16, atk: "+3", maxHp: 6, maxStress: 4, major: 13, severe: 26, weapon: "Longbow", damageType: "Physical", dice: "2d10+3", motives: "move through solid objects, rally troops, rehash old battles", experiences: "Ancient Knowledge +3", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Ghost</b>: The Captain has resistance to physical damage. Mark a Stress to move up to Close range through solid objects.", "<span class='cost-tag fear'>2 Fear</span> <b>Unending Battle</b>: Spend 2 Fear to return up to 1d4+1 defeated Spectral allies to the battle at the points where they first appeared (with no marked HP or Stress).", "<span class='cost-tag stress'>1 Stress</span> <b>Hold Fast</b>: When the Captain's Spectral allies are forced to make a reaction roll, you can mark a Stress to give those allies a +2 bonus to the roll.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Captain makes a successful attack against a PC, you gain a Fear."] },
  "spectral_guardian": { env: "Undead", name: "Spectral Guardian", tier: "2", type: "Standard", diff: 15, atk: "+1", maxHp: 4, maxStress: 3, major: 7, severe: 15, weapon: "Spear", damageType: "Physical", dice: "2d8+1", motives: "move through solid objects, protect treasure, rehash old battles", experiences: "Ancient Knowledge +2", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Ghost</b>: The Guardian has resistance to physical damage. Mark a Stress to move up to Close range through solid objects.", "<span class='cost-tag stress'>1 Stress</span> <b>Grave Blade</b>: Spend a Fear to make an attack against a target within Very Close range. On a success, deal 2d10+6 physical damage and the target must mark a Stress."] },
  "spy": { env: "Criminal Underworld", name: "Spy", tier: "2", type: "Social", diff: 15, atk: "-2", maxHp: 4, maxStress: 3, major: 8, severe: 17, weapon: "Dagger", damageType: "Physical", dice: "2d6+3", motives: "cut and run, disguise appearance, eavesdrop", experiences: "Espionage +3", features: ["<span class='cost-tag fear'>1 Fear</span> <b>Gathering Secrets</b>: Spend a Fear to describe how the Spy knows a secret about a PC in the scene.", "<span class='cost-tag stress'>1 Stress</span> <b>Fly on the Wall</b>: When a PC or group is discussing something sensitive, you can mark a Stress to reveal that the Spy is present in the scene, observing them. If the Spy escapes the scene to report their findings, you gain 1d4 Fear."] },
  "stonewraith": { env: "Arcane Threats", name: "Stonewraith", tier: "2", type: "Skulk", diff: 13, atk: "+3", maxHp: 6, maxStress: 3, major: 11, severe: 22, weapon: "Bite and Claws", damageType: "Physical", dice: "2d8+6", motives: "defend territory, isolate prey, stalk", experiences: "Stonesense +3", features: ["<span class='cost-tag'>Passive</span> <b>Stonestrider</b>: The Stonewraith can move through stone and earth as easily as air. While within stone or earth, they are Hidden and immune to all damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Rocky Ambush</b>: While Hidden, mark a Stress to leap into Melee range with a target within Very Close range. The target must succeed on an Agility or Instinct Reaction Roll (15) or take 2d8 physical damage and become temporarily Restrained.", "<span class='cost-tag fear'>1 Fear</span> <b>Avalanche Roar</b>: Spend a Fear to roar while within a cave and cause a cave-in. All targets within Close range must succeed on an Agility Reaction Roll (14) or take 2d10 physical damage. The rubble can be cleared with a Progress Countdown (8).", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Stonewraith makes a successful attack against a PC, you gain a Fear."] },
  "war_wizard": { env: "Arcane Threats", name: "War Wizard", tier: "2", type: "Ranged", diff: 16, atk: "+4", maxHp: 5, maxStress: 6, major: 11, severe: 23, weapon: "Staff", damageType: "Magic", dice: "2d10+4", motives: "develop new spells, seek power, shatter formations", experiences: "Magical Knowledge +2, Strategize +2", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Battle Teleport</b>: Before or after making a standard attack, you can mark a Stress to teleport to a location within Far range.", "<span class='cost-tag stress'>1 Stress</span> <b>Refresh Warding Sphere</b>: Mark a Stress to refresh the Wizard's \"Warding Sphere\" reaction.", "<span class='cost-tag fear'>1 Fear</span> <b>Eruption</b>: Spend a Fear and choose a point within Far range. A Very Close area around that point erupts into impassable terrain. All targets within that area must make an Agility Reaction Roll (14). Targets who fail take 2d10 physical damage and are thrown out of the area. Targets who succeed take half damage and aren't moved.", "<span class='cost-tag fear'>1 Fear</span> <b>Arcane Artillery</b>: Spend a Fear to unleash a precise hail of magical blasts. All targets in the scene must make an Agility Reaction Roll. Targets who fail take 2d12 magic damage. Targets who succeed take half damage.", "<span class='cost-tag'>Passive</span> <b>Warding Sphere</b>: When the Wizard takes damage from an attack within Close range, deal 2d6 magic damage to the attacker. This reaction can't be used again until the Wizard refreshes it with their \"Refresh Warding Sphere\" action."] },
  "adult_flickerfly": { env: "Beasts & Solos", name: "Adult Flickerfly", tier: "3", type: "Solo", diff: 17, atk: "+3", maxHp: 12, maxStress: 6, major: 20, severe: 35, weapon: "Wing Slash", damageType: "Physical", dice: "3d20", motives: "collect shiny things, hunt, nest, swoop", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Flickerfly can be spotlighted up to four times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag'>Passive</span> <b>Never Misses</b>: When the Flickerfly makes an attack, the target's Evasion is halved against the attack.", "<span class='cost-tag'>Passive</span> <b>Deadly Flight</b>: While flying, the Flickerfly can move up to Far range instead of Close range before taking an action.", "<span class='cost-tag fear'>1 Fear</span> <b>Whirlwind</b>: Spend a Fear to whirl, making an attack against all targets within Very Close range. Targets the Flickerfly succeeds against take 3d8 direct physical damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Mind Dance</b>: Mark a Stress to create a magically dazzling display that grapples the minds of nearby foes. All targets within Close range must make an Instinct Reaction Roll. For each target who failed, you gain a Fear and the Flickerfly learns one of the target's fears.", "<span class='cost-tag'>Passive</span> <b>Hallucinatory Breath</b>: Countdown (Loop 1d6). When the Flickerfly takes damage for the first time, activate the countdown. When it triggers, the Flickerfly breathes hallucinatory gas on all targets in front of them up to Far range. Targets must make an Instinct Reaction Roll or be tormented by fearful hallucinations. Targets whose fears are known to the Flickerfly have disadvantage on this roll. Targets who fail lose 2 Hope and take 3d8+3 direct magic damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Uncanny Reflexes</b>: When the Flickerfly takes damage from an attack within Close range, you can mark a Stress to take half damage."] },
  "demon_of_avarice": { env: "Demons", name: "Demon Of Avarice", tier: "3", type: "Support", diff: 17, atk: "+2", maxHp: 6, maxStress: 5, major: 15, severe: 29, weapon: "Hungry Maw", damageType: "Magic", dice: "3d6+5", motives: "consume, fuel greed, sow dissent", experiences: "Manipulation +3", features: ["<span class='cost-tag'>Passive</span> <b>Money Talks</b>: Attacks against the Demon are made with disadvantage unless the attacker spends a handful of gold. This Demon starts with a number of handfuls equal to the number of PCs. When a target marks HP from the Demon's standard attack, they can spend a handful of gold instead of marking HP (1 handful per HP). Add a handful of gold to the Demon for each handful of gold spent by PCs on this feature.", "<span class='cost-tag'>Passive</span> <b>Numbers Must Go Up</b>: Add a bonus to the Demon's attack rolls equal to the number of handfuls of gold they have.", "<span class='cost-tag'>Passive</span> <b>Money Is Time</b>: Spend 3 handfuls of gold (or a Fear) to spotlight 1d4+1 allies."] },
  "demon_of_despair": { env: "Demons", name: "Demon Of Despair", tier: "3", type: "Skulk", diff: 17, atk: "+3", maxHp: 6, maxStress: 5, major: 18, severe: 35, weapon: "Miasma Bolt", damageType: "Magic", dice: "3d6+1", motives: "make fear contagious, stick to the shadows, undermine resolve", experiences: "Manipulation +3", features: ["<span class='cost-tag'>Passive</span> <b>Depths of Despair</b>: The Demon deals double damage to PCs with 0 Hope.", "<span class='cost-tag fear'>1 Fear</span> <b>Your Struggle Is Pointless</b>: Spend a Fear to weigh down the spirits of all PCs within Far range. All targets affected replace their Hope Die with a d8 until they roll a success with Hope or their next rest.", "<span class='cost-tag stress'>1 Stress</span> <b>Your Friends Will Fail You</b>: When a PC fails with Fear, you can mark a Stress to cause all other PCs within Close range to lose a Hope.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Demon makes a successful attack against a PC, you gain a Fear."] },
  "demon_of_hubris": { env: "Demons", name: "Demon Of Hubris", tier: "3", type: "Leader", diff: 18, atk: "+4", maxHp: 7, maxStress: 5, major: 18, severe: 36, weapon: "Perfect Spear", damageType: "Physical", dice: "3d10", motives: "condescend, declare premature victory, prove superiority", experiences: "Manipulation +2", features: ["<span class='cost-tag'>Passive</span> <b>Terrifying</b>: When the Demon makes a successful attack, all PCs within Far range must lose a Hope and you gain a Fear.", "<span class='cost-tag stress'>2 Stress</span> <b>Double or Nothing</b>: When a PC within Far range fails a roll, they can choose to reroll their Fear Die and take the new result. If they still fail, they mark 2 Stress and the Demon clears a Stress.", "<span class='cost-tag stress'>1 Stress</span> <b>Unparalleled Skill</b>: Mark a Stress to deal the Demon's standard attack damage to a target within Close range.", "<span class='cost-tag fear'>1 Fear</span> <b>The Root of Villainy</b>: Spend a Fear to spotlight two other Demons within Far range.", "<span class='cost-tag stress'>1 Stress</span> <b>You Pale in Comparison</b>: When a PC fails a roll within Close range of the Demon, they must mark a Stress."] },
  "demon_of_jealousy": { env: "Demons", name: "Demon Of Jealousy", tier: "3", type: "Ranged", diff: 17, atk: "+4", maxHp: 6, maxStress: 6, major: 17, severe: 30, weapon: "Psychic Assault", damageType: "Magic", dice: "3d8+3", motives: "join in on others' success, take what belongs to others, hold grudges", experiences: "Manipulation +3", features: ["<span class='cost-tag'>Passive</span> <b>Unprotected Mind</b>: The Demon's standard attack deals direct damage.", "<span class='cost-tag'>Passive</span> <b>My Turn</b>: When the Demon marks HP from an attack, spend a number of Fear equal to the HP marked by the Demon to cause the attacker to mark the same number of HP.", "<span class='cost-tag stress'>1 Stress</span> <b>Rivalry</b>: When a creature within Close range takes damage from a different adversary, you can mark a Stress to add a d4 to the damage roll.", "<span class='cost-tag fear'>1 Fear</span> <b>What's Yours Is Mine</b>: When a PC takes Severe damage within Very Close range of the Demon, you can spend a Fear to cause the target to make a Finesse Reaction Roll. On a failure, the Demon seizes one item or consumable of their choice from the target's inventory."] },
  "demon_of_wrath": { env: "Demons", name: "Demon Of Wrath", tier: "3", type: "Bruiser", diff: 17, atk: "+3", maxHp: 7, maxStress: 5, major: 22, severe: 40, weapon: "Fists", damageType: "Magic", dice: "3d8+1", motives: "fuel anger, impress rivals, wreak havoc", experiences: "Intimidation +2", features: ["<span class='cost-tag'>Passive</span> <b>Anger Unrelenting</b>: The Demon's attacks deal direct damage.", "<span class='cost-tag fear'>1 Fear</span> <b>Battle Lust</b>: Spend a Fear to boil the blood of all PCs within Far range. They use a d20 as their Fear Die until the end of the scene.", "<span class='cost-tag stress'>1 Stress</span> <b>Retaliation</b>: When the Demon takes damage from an attack within Close range, you can mark a Stress to make a standard attack against the attacker.", "<span class='cost-tag'>Passive</span> <b>Blood and Souls</b>: Countdown (Loop 6). Activate the first time an attack is made within sight of the Demon. It ticks down when a PC takes a violent action. When it triggers, summon 1d4 Minor Demons, who appear at Close range."] },
  "dire_bat": { env: "Beasts & Solos", name: "Dire Bat", tier: "3", type: "Skulk", diff: 14, atk: "+2", maxHp: 5, maxStress: 3, major: 16, severe: 30, weapon: "Claws and Teeth", damageType: "Physical", dice: "2d6+7", motives: "dive-bomb, hide, protect leader", experiences: "Bloodthirsty +3", features: ["<span class='cost-tag'>Passive</span> <b>Flying</b>: While flying, the Bat gains a +3 bonus to their Difficulty.", "<span class='cost-tag stress'>1 Stress</span> <b>Screech</b>: Mark a Stress to send a high-pitch screech out toward all targets in front of the Bat within Far range. Those targets must mark 1d4 Stress.", "<span class='cost-tag stress'>1 Stress</span> <b>Guardian</b>: When an allied Vampire marks HP, you can mark a Stress to fl y into Melee range of the attacker and make an attack with advantage against them. On a success, deal 2d6+2 physical damage."] },
  "dryad": { env: "Forest & Fae", name: "Dryad", tier: "3", type: "Leader", diff: 16, atk: "+4", maxHp: 8, maxStress: 5, major: 24, severe: 38, weapon: "Deadfall Shortbow", damageType: "Physical", dice: "3d10+1", motives: "command, cultivate, drive out, preserve the forest", experiences: "Forest Knowledge +4", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Bramble Patch</b>: Mark a Stress to target a point within Far range. Create a patch of thorns that covers an area within Close range of that point. All targets within that area take 2d6+2 physical damage when they act. A target must succeed on a Finesse Roll or deal more than 20 damage to the Dryad with an attack to leave the area.", "<span class='cost-tag fear'>1 Fear</span> <b>Grow Saplings</b>: Spend a Fear to grow three Treant Sapling Minions, who appear at Close range and immediately take the spotlight.", "<span class='cost-tag fear'>1 Fear</span> <b>We Are All One</b>: When an ally dies within Close range, you can spend a Fear to clear 2 HP and 2 Stress as the fallen ally's life force is returned to the forest."] },
  "elemental_spark": { env: "Arcane Threats", name: "Elemental Spark", tier: "3", type: "Minion", diff: 15, atk: "+0", maxHp: 1, maxStress: 1, major: 0, severe: 0, weapon: "Bursts of Fire", damageType: "Magic", dice: "5", motives: "blast, consume, gain mass", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Elemental is defeated when they take any damage. For every 9 damage a PC deals to the Elemental, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Elemental Sparks within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 5 physical damage each. Combine this damage."] },
  "greater_earth_elemental": { env: "Arcane Threats", name: "Greater Earth Elemental", tier: "3", type: "Bruiser", diff: 17, atk: "+7", maxHp: 10, maxStress: 4, major: 22, severe: 40, weapon: "Boulder Fist", damageType: "Physical", dice: "3d10+1", motives: "avalanche, knock over, pummel", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Slow</b>: When you spotlight the Elemental and they don't have a token on their stat block, they can't act yet. Place a token on their stat block and describe what they're preparing to do. When you spotlight the Elemental and they have a token on their stat block, clear the token and they can act.", "<span class='cost-tag'>Passive</span> <b>Crushing Blows</b>: When the Elemental makes a successful attack, the target must mark an Armor Slot without receiving its benefits (they can still use armor to reduce the damage). If they can't mark an Armor Slot, they must mark an additional HP.", "<span class='cost-tag'>Passive</span> <b>Immovable Object</b>: An attack that would move the Elemental moves them two fewer ranges (for example, Far becomes Very Close). When the Elemental takes physical damage, reduce it by 7.", "<span class='cost-tag stress'>1 Stress</span> <b>Rockslide</b>: Mark a Stress to create a rockslide that buries the land in front of Elemental within Close range with rockfall. All targets in this area must make an Agility Reaction Roll (19). Targets who fail take 2d12+5 physical damage and become Vulnerable until their next roll with Hope. Targets who succeed take half damage.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Elemental makes a successful attack against a PC, you gain a Fear."] },
  "greater_water_elemental": { env: "Arcane Threats", name: "Greater Water Elemental", tier: "3", type: "Support", diff: 17, atk: "+3", maxHp: 5, maxStress: 5, major: 17, severe: 34, weapon: "Crashing Wave", damageType: "Magic", dice: "3d4+1", motives: "deluge, disperse, drown", experiences: "", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Water Jet</b>: Mark a Stress to attack a target within Very Close range. On a success, deal 2d4+7 physical damage and the target's next action has disadvantage. On a failure, the target must mark a Stress.", "<span class='cost-tag fear'>1 Fear</span> <b>Drowning Embrace</b>: Spend a Fear to make an attack against all targets within Very Close range. Targets the Elemental succeeds against become Restrained and Vulnerable as they begin drowning. A target can break free, ending both conditions, with a successful Strength or Instinct Roll.", "<span class='cost-tag stress'>1 Stress</span> <b>High Tide</b>: When the Elemental makes a successful standard attack, you can mark a Stress to knock the target back to Close range."] },
  "head_vampire": { env: "Undead", name: "Head Vampire", tier: "3", type: "Leader", diff: 17, atk: "+5", maxHp: 6, maxStress: 6, major: 22, severe: 42, weapon: "Rapier", damageType: "Physical", dice: "2d20+4", motives: "create thralls, charm, command, fl y, intimidate", experiences: "Aristocrat +3", features: ["<span class='cost-tag'>Passive</span> <b>Terrifying</b>: When the Vampire makes a successful attack, all PCs within Far range lose a Hope and you gain a Fear.", "<span class='cost-tag'>Passive</span> <b>Look into My Eyes</b>: A creature who moves into Melee range of the Vampire must make an Instinct Reaction Roll. On a failure, you gain 1d4 Fear.", "<span class='cost-tag stress'>Mark HP</span> <b>Feed on Followers</b>: When the Vampire is within Melee range of an ally, they can cause the ally to mark a HP. The Vampire then clears a HP.", "<span class='cost-tag fear'>2 Fear</span> <b>The Hunt Is On</b>: Spend 2 Fear to summon 1d4 Vampires, who appear at Far range and immediately take the spotlight.", "<span class='cost-tag stress'>Mark HP</span> <b>Lifesuck</b>: When the Vampire is spotlighted, roll a d8. On a result of 6 or higher, all targets within Very Close range must mark a HP."] },
  "huge_green_ooze": { env: "Oozes", name: "Huge Green Ooze", tier: "3", type: "Skulk", diff: 15, atk: "+3", maxHp: 7, maxStress: 4, major: 15, severe: 30, weapon: "Ooze Appendage", damageType: "Magic", dice: "3d8+1", motives: "camouflage, creep up, envelop, multiply", experiences: "Blend In +3", features: ["<span class='cost-tag'>Passive</span> <b>Slow</b>: When you spotlight the Ooze and they don't have a token on their stat block, they can't act yet. Place a token on their stat block and describe what they're preparing to do. When you spotlight the Ooze and they have a token on their stat block, clear the token and they can act.", "<span class='cost-tag'>Passive</span> <b>Acidic Form</b>: When the Ooze makes a successful attack, the target must mark an Armor Slot without receiving its benefits (they can still use armor to reduce the damage). If they can't mark an Armor Slot, they must mark an additional HP.", "<span class='cost-tag stress'>2 Stress</span> <b>Envelop</b>: Make an attack against a target within Melee range. On a success, the Ooze Envelops them and the target must mark 2 Stress. While Enveloped, the target must mark an additional Stress every time they make an action roll. When the Ooze takes Severe damage, all Enveloped targets are freed and the condition is cleared.", "<span class='cost-tag fear'>1 Fear</span> <b>Split</b>: When the Ooze has 4 or more HP marked, you can spend a Fear to split them into two Green Oozes (with no marked HP or Stress). Immediately spotlight both of them."] },
  "hydra": { env: "Beasts & Solos", name: "Hydra", tier: "3", type: "Solo", diff: 18, atk: "+3", maxHp: 10, maxStress: 5, major: 19, severe: 35, weapon: "Bite", damageType: "Physical", dice: "2d12+2", motives: "devour, regenerate, terrify", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Many-Headed Menace</b>: The Hydra begins with three heads and can have up to five. When the Hydra takes Major or greater damage, they lose a head.", "<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Hydra can be spotlighted X times per GM turn, where X is the Hydra's number of heads. Spend Fear as usual to spotlight them.", "<span class='cost-tag fear'>1 Fear</span> <b>Regeneration</b>: If the Hydra has any marked HP, spend a Fear to clear a HP and grow two heads.", "<span class='cost-tag'>Passive</span> <b>Terrifying Chorus</b>: All PCs within Far range lose 2 Hope.", "<span class='cost-tag'>Passive</span> <b>Magical Weakness</b>: When the Hydra takes magic damage, they become Dazed until the next roll with Fear. While Dazed, they can't use their Regeneration action but are immune to magic damage."] },
  "monarch": { env: "Nobility & Court", name: "Monarch", tier: "3", type: "Social", diff: 16, atk: "+0", maxHp: 6, maxStress: 5, major: 16, severe: 32, weapon: "Warhammer", damageType: "Physical", dice: "3d6+3", motives: "control vassals, destroy rivals, forge a legacy", experiences: "History +3, Nobility +3", features: ["<span class='cost-tag fear'>1 Fear</span> <b>Execute Them!</b>: Spend a Fear per PC in the party to have the group condemned for crimes real or imagined. A PC who succeeds on a Presence Roll can demand trial by combat or another special form of trial.", "<span class='cost-tag stress'>1 Stress</span> <b>Crownsguard</b>: Once per scene, mark a Stress to summon six Tier 3 Minions, who appear at Close range to enforce the Monarch's will.", "<span class='cost-tag fear'>1 Fear</span> <b>Casus Belli</b>: Long-Term Countdown (8). Spend a Fear to activate after the Monarch's desire for war is first revealed. When it triggers, the Monarch has a reason to rally the nation to war and the support to act on that reason. You gain 1d4 Fear."] },
  "oak_treant": { env: "Forest & Fae", name: "Oak Treant", tier: "3", type: "Bruiser", diff: 17, atk: "+2", maxHp: 7, maxStress: 4, major: 22, severe: 40, weapon: "Branch", damageType: "Physical", dice: "3d8+2", motives: "hide in plain sight, preserve the forest, root down, swing branches", experiences: "Forest Knowledge +3", features: ["<span class='cost-tag'>Passive</span> <b>Just a Tree</b>: Before they make their first attack in a fi ght or after they become Hidden, the Treant is indistinguishable from other trees until they next act or a PC succeeds on an Instinct Roll to identify them.", "<span class='cost-tag stress'>1 Stress</span> <b>Seed Barrage</b>: Mark a Stress and make an attack against up to three targets within Close range, pummeling them with giant acorns. Targets the Treant succeeds against take 2d10+5 physical damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Take Root</b>: Mark a Stress to Root the Treant in place. The Treant is Restrained while Rooted, and can end this effect instead of moving while they are spotlighted. While Rooted, the Treant has resistance to physical damage."] },
  "stag_knight": { env: "Forest & Fae", name: "Stag Knight", tier: "3", type: "Standard", diff: 17, atk: "+3", maxHp: 7, maxStress: 5, major: 19, severe: 36, weapon: "Bramble Sword", damageType: "Physical", dice: "3d8+3", motives: "isolate, maneuver, protect the forest, weed the unwelcome", experiences: "Forest Knowledge +3", features: ["<span class='cost-tag'>Passive</span> <b>From Above</b>: When the Knight succeeds on a standard attack from above a target, they deal 3d12+3 physical damage instead of their standard damage.", "<span class='cost-tag fear'>1 Fear</span> <b>Blade of the Forest</b>: Spend a Fear to make an attack against all targets within Very Close range. Targets the Knight succeeds against take physical damage equal to 3d4 + the target's Major threshold.", "<span class='cost-tag stress'>1 Stress</span> <b>Thorny Armor</b>: When the Knight takes damage from an attack within Melee range, you can mark a Stress to deal 1d10+5 physical damage to the attacker."] },
  "treant_sapling": { env: "Forest & Fae", name: "Treant Sapling", tier: "3", type: "Minion", diff: 14, atk: "+0", maxHp: 1, maxStress: 1, major: 0, severe: 0, weapon: "Branches", damageType: "Physical", dice: "8", motives: "blend in, preserve the forest, pummel, surround", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Sapling is defeated when they take any damage. For every 6 damage a PC deals to the Sapling, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Treant Saplings within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 8 physical damage each. Combine this damage."] },
  "vampire": { env: "Undead", name: "Vampire", tier: "3", type: "Standard", diff: 16, atk: "+3", maxHp: 5, maxStress: 4, major: 18, severe: 35, weapon: "Rapier", damageType: "Physical", dice: "3d8", motives: "bite, charm, deceive, feed, intimidate", experiences: "Nocturnal Hunter +3", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Draining Bite</b>: Make an attack against a target within Melee range. On a success, deal 5d4 physical damage. A target who marks HP from this attack loses a Hope and must mark a Stress. The Vampire then clears a HP.", "<span class='cost-tag fear'>1 Fear</span> <b>Mistform</b>: When the Vampire takes physical damage, you can spend a Fear to take half damage."] },
  "vault_guardian_gaoler": { env: "Vault Guardians", name: "Vault Guardian Gaoler", tier: "3", type: "Support", diff: 16, atk: "+2", maxHp: 5, maxStress: 3, major: 19, severe: 33, weapon: "Body Bash", damageType: "Physical", dice: "3d6+2", motives: "carry away, entrap, protect, pummel", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Blocking Shield</b>: Creatures within Melee range of the Gaoler have disadvantage on attack rolls against them. Creatures trapped inside the Gaoler are immune to this feature.", "<span class='cost-tag stress'>1 Stress</span> <b>Lock Up</b>: Mark a Stress to make an attack against a target within Very Close range. On a success, the target is Restrained within the Gaoler until freed with a successful Strength Roll (18). While Restrained, the target can only attack the Gaoler. 95"] },
  "vault_guardian_sentinel": { env: "Vault Guardians", name: "Vault Guardian Sentinel", tier: "3", type: "Bruiser", diff: 17, atk: "+3", maxHp: 6, maxStress: 3, major: 21, severe: 40, weapon: "Charged Mace", damageType: "Physical", dice: "2d12+1", motives: "destroy at any cost, expunge, protect", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Kinetic Slam</b>: Targets who take damage from the Sentinel's standard attack are knocked back to Very Close range.", "<span class='cost-tag stress'>1 Stress</span> <b>Box In</b>: Mark a Stress to choose a target within Very Close range to focus on. That target has disadvantage on attack rolls when they're within Very Close range of the Sentinel. The Sentinel can only focus on one target at a time.", "<span class='cost-tag fear'>1 Fear</span> <b>Mana Bolt</b>: Spend a Fear to lob explosive magic at a point within Far range. All targets within Very Close range of that point must make an Agility Reaction Roll. Targets who fail take 2d8+20 magic damage and are knocked back to Close range. Targets who succeed take half damage and aren't knocked back.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Sentinel makes a successful attack against a PC, you gain a Fear."] },
  "vault_guardian_turret": { env: "Vault Guardians", name: "Vault Guardian Turret", tier: "3", type: "Ranged", diff: 16, atk: "+3", maxHp: 5, maxStress: 4, major: 20, severe: 32, weapon: "Magitech Cannon", damageType: "Magic", dice: "3d10+3", motives: "concentrate fire, lock down, mark, protect", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Slow Firing</b>: When you spotlight the Turret and they don't have a token on their stat block, they can't make a standard attack. Place a token on their stat block and describe what they're preparing to do. When you spotlight the Turret and they have a token on their stat block, clear the token and they can attack.", "<span class='cost-tag fear'>1 Fear</span> <b>Mark Target</b>: Spend a Fear to Mark a target within Far range until the Turret is destroyed or the Marked target becomes Hidden. While the target is Marked, their Evasion is halved.", "<span class='cost-tag stress'>1 Stress</span> <b>Concentrate Fire</b>: When another adversary deals damage to a target within Far range of the Turret, you can mark a Stress to add the Turret's standard attack damage to the damage roll.", "<span class='cost-tag'>Passive</span> <b>Detonation</b>: When the Turret is destroyed, they explode. All targets within Close range must make an Agility Reaction Roll. Targets who fail take 3d20 physical damage. Targets who succeed take half damage."] },
  "young_ice_dragon": { env: "Beasts & Solos", name: "Young Ice Dragon", tier: "3", type: "Solo", diff: 18, atk: "+7", maxHp: 10, maxStress: 6, major: 21, severe: 41, weapon: "Bite and Claws", damageType: "Physical", dice: "4d10", motives: "avalanche, defend lair, fl y, freeze, defend what is mine, maul", experiences: "Protect What Is Mine +3", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Dragon can be spotlighted up to three times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag stress'>1 Stress</span> <b>Rend and Crush</b>: If a target damaged by the Dragon doesn't mark an Armor Slot to reduce the damage, they must mark a Stress.", "<span class='cost-tag'>Passive</span> <b>No Hope</b>: When a PC rolls with Fear while within Far range of the Dragon, they lose a Hope.", "<span class='cost-tag fear'>2 Fear</span> <b>Blizzard Breath</b>: Spend 2 Fear to release an icy whorl in front of the Dragon within Close range. All targets in this area must make an Agility Reaction Roll. Targets who fail take 4d6+5 magic damage and are Restrained by ice until they break free with a successful Strength Roll. Targets who succeed must mark 2 Stress or take half damage.", "<span class='cost-tag fear'>1 Fear</span> <b>Avalanche</b>: Spend a Fear to have the Dragon unleash a huge downfall of snow and ice, covering all other creatures within Far range. All targets within this area must succeed on an Instinct Reaction Roll or be buried in snow and rocks, becoming Vulnerable until they dig themselves out from the debris. For each PC that fails the reaction roll, you gain a Fear.", "<span class='cost-tag stress'>1 Stress</span> <b>Frozen Scales</b>: When a creature makes a successful attack against the Dragon from within Very Close range, they must mark a Stress and become Chilled until their next rest or they clear a Stress. While they are Chilled, they have disadvantage on attack rolls.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Dragon makes a successful attack against a PC, you gain a Fear."] },
  "arch_necromancer": { env: "Undead", name: "Arch-necromancer", tier: "4", type: "Leader", diff: 21, atk: "+6", maxHp: 9, maxStress: 8, major: 33, severe: 66, weapon: "Necrotic Blast", damageType: "Magic", dice: "4d12+8", motives: "corrupt, decay, fl ee to fi ght another day, resurrect", experiences: "Forbidden Knowledge +3, Wisdom of Centuries +3", features: ["<span class='cost-tag stress'>1 Stress</span> <b>Dance of Death</b>: Mark a Stress to spotlight 1d4 allies. Attacks they make while spotlighted in this way deal half damage, or full damage if you spend a Fear.", "<span class='cost-tag stress'>2 Stress</span> <b>Beam of Decay</b>: Mark 2 Stress to cause all targets within Far range to make a Strength Reaction Roll. Targets who fail take 2d20+12 magic damage and you gain a Fear. Targets who succeed take half damage. A target who marks 2 or more HP must also mark 2 Stress and becomes Vulnerable until they roll with Hope.", "<span class='cost-tag fear'>1 Fear</span> <b>Open the Gates of Death</b>: Spend a Fear to summon a Zombie Legion, which appears at Close range and immediately takes the spotlight.", "<span class='cost-tag fear'>1 Fear</span> <b>Not Today, My Dears</b>: When the Necromancer has marked 7 or more of their HP, you can spend a Fear to have them teleport away to a safe location to recover. A PC who succeeds on an Instinct Roll can trace the teleportation magic to their destination.", "<span class='cost-tag'>Passive</span> <b>Your Life Is Mine</b>: Countdown (Loop 2d6). When the Necromancer has marked 6 or more of their HP, activate the countdown. When it triggers, deal 2d10+6 direct magic damage to a target within Close range. The Necromancer then clears a number of Stress or HP equal to the number of HP marked by the target from this attack."] },
  "fallen_shock_troop": { env: "The Fallen", name: "Fallen Shock Troop", tier: "4", type: "Minion", diff: 18, atk: "+2", maxHp: 1, maxStress: 1, major: 0, severe: 0, weapon: "Cursed Axe", damageType: "Physical", dice: "12", motives: "crush, dominate, earn relief, punish", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Shock Troop is defeated when they take any damage. For every 12 damage a PC deals to the Shock Troop, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag'>Passive</span> <b>Aura of Doom</b>: When a PC marks HP from an attack by the Shock Troop, they lose a Hope.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Fallen Shock Troops within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 12 physical damage each. Combine this damage."] },
  "fallen_sorcerer": { env: "The Fallen", name: "Fallen Sorcerer", tier: "4", type: "Support", diff: 19, atk: "+4", maxHp: 6, maxStress: 5, major: 26, severe: 42, weapon: "Corrupted Staff", damageType: "Magic", dice: "4d6+10", motives: "acquire, dishearten, dominate, torment", experiences: "Ancient Knowledge +2", features: ["<span class='cost-tag fear'>1 Fear</span> <b>Confl agration</b>: Spend a Fear to unleash an all-consuming firestorm and make an attack against all targets within Close range. Targets the Sorcerer succeeds against take 2d10+6 direct magic damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Nightmare Tableau</b>: Mark a Stress to trap a target within Far range in a powerful illusion of their worst fears. While trapped, the target is Restrained and Vulnerable until they break free, ending both conditions, with a successful Instinct Roll.", "<span class='cost-tag'>Passive</span> <b>Slippery</b>: When the Sorcerer takes damage from an attack, they can teleport up to Far range.", "<span class='cost-tag stress'>1 Stress</span> <b>Shackles of Guilt</b>: Countdown (Loop 2d6). When the Sorcerer is in the spotlight for the first time, activate the countdown. When it triggers, all targets within Far range become Vulnerable and must mark a Stress as they relive their greatest regrets. A target can break free from their regret with a successful Presence or Strength Roll. When a PC fails to break free, they lose a Hope. FALLEN WARLORD:"] },
  "fallen_warlord_undefeated_champion": { env: "The Fallen", name: "Fallen Warlord: Undefeated Champion", tier: "4", type: "Solo", diff: 18, atk: "+8", maxHp: 11, maxStress: 5, major: 35, severe: 58, weapon: "Heart-Shattering Sword", damageType: "Physical", dice: "4d12+13", motives: "dispatch merciless death, punish the defiant, secure victory at any cost", experiences: "Conquest +3, History +2, Intimidation +3", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Undefeated Champion can be spotlighted up to three times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag'>Passive</span> <b>Faltering Armor</b>: When the Undefeated Champion takes damage, reduce it by 1d10.", "<span class='cost-tag stress'>1 Stress</span> <b>Shattering Strike</b>: Mark a Stress to make a standard attack against all targets within Very Close range. PCs the Champion succeeds against lose a number of Hope equal to the HP they marked from this attack.", "<span class='cost-tag fear'>1 Fear</span> <b>Endless Legions</b>: Spend a Fear to summon a number of Fallen Shock Troops equal to twice the number of PCs. The Shock Troops appear at Far range.", "<span class='cost-tag'>Passive</span> <b>Circle of Defilement</b>: Countdown (1d8). When the Undefeated Champion is in the spotlight for the first time, activate the countdown. When it triggers, activate a magical circle covering an area within Far range of the Champion. A target within that area is Vulnerable until they leave the circle. The circle can be removed by dealing Severe damage to the Undefeated Champion.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Undefeated Champion makes a successful attack against a PC, you gain a Fear.", "<span class='cost-tag'>Passive</span> <b>Doombringer</b>: When a target marks HP from an attack by the Undefeated Champion, all PCs within Far range of the target lose a Hope."] },
  "hallowed_archer": { env: "Divine & Oracles", name: "Hallowed Archer", tier: "4", type: "Ranged", diff: 19, atk: "+4", maxHp: 3, maxStress: 2, major: 25, severe: 45, weapon: "Sanctifi ed Longbow", damageType: "Physical", dice: "4d8+8", motives: "focus fire, obey, reposition, volley", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Punish the Guilty</b>: The Archer deals double damage to targets marked Guilty by a High Seraph.", "<span class='cost-tag stress'>1 Stress</span> <b>Divine Volley</b>: Mark a Stress to make a standard attack against up to three targets."] },
  "hallowed_soldier": { env: "Divine & Oracles", name: "Hallowed Soldier", tier: "4", type: "Minion", diff: 18, atk: "+2", maxHp: 1, maxStress: 2, major: 0, severe: 0, weapon: "Sword and Shield", damageType: "Physical", dice: "10", motives: "obey, outmaneuver, punish, swarm", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Soldier is defeated when they take any damage. For every 13 damage a PC deals to the Soldier, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag fear'>1 Fear</span> <b>Divine Flight</b>: While the Soldier is flying, spend a Fear to move up to Far range instead of Close range before taking an action.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Hallowed Soldiers within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 10 physical damage each. Combine this damage."] },
  "high_seraph": { env: "Divine & Oracles", name: "High Seraph", tier: "4", type: "Leader", diff: 20, atk: "+8", maxHp: 7, maxStress: 5, major: 37, severe: 70, weapon: "Holy Sword", damageType: "Physical", dice: "4d10+10", motives: "enforce dogma, fl y, pronounce judgment, smite", experiences: "Divine Knowledge +3", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Seraph can be spotlighted up to three times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag fear'>1 Fear</span> <b>Divine Flight</b>: While the Seraph is flying, spend a Fear to move up to Far range instead of Close range before taking an action.", "<span class='cost-tag fear'>1 Fear</span> <b>Judgment</b>: Spend a Fear to make a target Guilty in the eyes of the Seraph's god until the Seraph is defeated. While Guilty, the target doesn't gain Hope on a result with Hope. When the Seraph succeeds on a standard attack against a Guilty target, they deal Severe damage instead of their standard damage. The Seraph can only mark one target at a time.", "<span class='cost-tag stress'>1 Stress</span> <b>God Rays</b>: Mark a Stress to refl ect a sliver of divinity as a searing beam of light that hits up to twenty targets within Very Far range. Targets must make a Presence Reaction Roll, with disadvantage if they are marked Guilty. Targets who fail take 4d6+12 magic damage. Targets who succeed take half damage.", "<span class='cost-tag fear'>1 Fear</span> <b>We Are One</b>: Once per scene, spend a Fear to spotlight all other adversaries within Far range. Attacks they make while spotlighted in this way deal half damage."] },
  "kraken": { env: "Beasts & Solos", name: "Kraken", tier: "4", type: "Solo", diff: 20, atk: "+7", maxHp: 11, maxStress: 8, major: 35, severe: 70, weapon: "Tentacles", damageType: "Physical", dice: "4d12+10", motives: "consume, crush, drown, grapple", experiences: "Swimming +3", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Kraken can be spotlighted up to three times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag'>Passive</span> <b>Many Tentacles</b>: While the Kraken has 7 or fewer marked HP, they can make their standard attack against two targets within range.", "<span class='cost-tag stress'>1 Stress</span> <b>Grapple and Drown</b>: Make an attack roll against a target within Close range. On a success, mark a Stress to grab them with a tentacle and drag them beneath the water. The target is Restrained and Vulnerable until they break free with a successful Strength Roll or the Kraken takes Major or greater damage. While Restrained and Vulnerable in this way, a target must mark a Stress when they make an action roll.", "<span class='cost-tag stress'>1 Stress</span> <b>Boiling Blast</b>: Spend a Fear to spew a line of boiling water at any number of targets in a line up to Far range. All targets must succeed on an Agility Reaction Roll or take 4d6+9 physical damage. If a target marks an Armor Slot to reduce the damage, they must also mark a Stress.", "<span class='cost-tag'>Passive</span> <b>Momentum</b>: When the Kraken makes a successful attack against a PC, you gain a Fear."] },
  "oracle_of_doom": { env: "Divine & Oracles", name: "Oracle Of Doom", tier: "4", type: "Solo", diff: 20, atk: "+8", maxHp: 11, maxStress: 10, major: 38, severe: 68, weapon: "Psychic Attack", damageType: "Magic", dice: "4d8+9", motives: "change environment, condemn, dishearten, toss aside", experiences: "Boundless Knowledge +4", features: ["<span class='cost-tag'>Passive</span> <b>Terrifying</b>: When the Oracle makes a successful attack, all PCs within Far range lose a Hope and you gain a Fear.", "<span class='cost-tag stress'>1 Stress</span> <b>Walls Closing In</b>: When a creature rolls a failure while within Very Far range of the Oracle, they must mark a Stress.", "<span class='cost-tag fear'>1 Fear</span> <b>Pronounce Fate</b>: Spend a Fear to present a target within Far range with a vision of their personal nightmare. The target must make a Knowledge Reaction Roll. On a failure, they lose all Hope and take 2d20+4 direct magic damage. On a success, they take half damage and lose a Hope.", "<span class='cost-tag fear'>2 Fear</span> <b>Summon Tormentors</b>: Once per day, spend 2 Fear to summon 2d4 Tier 2 or below Minions relevant to one of the PC's personal nightmares. They appear at Close range relative to that PC.", "<span class='cost-tag'>Passive</span> <b>Ominous Knowledge</b>: When the Oracle sees a mortal creature, they instantly know one of their personal nightmares.", "<span class='cost-tag stress'>1 Stress</span> <b>Vengeful Fate</b>: When the Oracle marks HP from an attack within Very Close range, you can mark a Stress to knock the attacker back to Far range and deal 2d10+4 physical damage."] },
  "outer_realms_abomination": { env: "Outer Realms", name: "Outer Realms Abomination", tier: "4", type: "Bruiser", diff: 19, atk: "+2", maxHp: 7, maxStress: 5, major: 35, severe: 71, weapon: "Massive Pseudopod", damageType: "Magic", dice: "4d6+13", motives: "demolish, devour, undermine", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Chaotic Form</b>: When the Abomination attacks, roll 2d4 and use the result as their attack modifi er.", "<span class='cost-tag'>Passive</span> <b>Disorienting Presence</b>: When a target takes damage from the Abomination, they must make an Instinct Reaction Roll. On a failure, they gain disadvantage on their next action roll and you gain a Fear.", "<span class='cost-tag fear'>1 Fear</span> <b>Reality Quake</b>: Spend a Fear to rattle the edges of reality within Far range of the Abomination. All targets within that area must succeed on a Knowledge Reaction Roll or become Unstuck from reality until the end of the scene. When an Unstuck target spends Hope or marks Armor Slots, HP, or Stress, they must double the amount spent or marked.", "<span class='cost-tag'>Passive</span> <b>Unreal Form</b>: When the Abomination takes damage, reduce it by 1d20. If the Abomination marks 1 or fewer Hit Points from a successful attack against them, you gain a Fear."] },
  "outer_realms_corrupter": { env: "Outer Realms", name: "Outer Realms Corrupter", tier: "4", type: "Support", diff: 19, atk: "+7", maxHp: 4, maxStress: 3, major: 27, severe: 47, weapon: "Corroding Pseudopod", damageType: "Magic", dice: "4d8+5", motives: "confuse, distract, overwhelm", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Will-Shattering Touch</b>: When a PC takes damage from the Corrupter, they lose a Hope.", "<span class='cost-tag stress'>2 Stress</span> <b>Disgorge Reality Flotsam</b>: Mark a Stress to spew partially digested portions of consumed realities at all targets within Close range. Targets must succeed on a Knowledge Reaction Roll or mark 2 Stress."] },
  "outer_realms_thrall": { env: "Outer Realms", name: "Outer Realms Thrall", tier: "4", type: "Minion", diff: 17, atk: "+3", maxHp: 1, maxStress: 1, major: 0, severe: 0, weapon: "Claws and Teeth", damageType: "Physical", dice: "11", motives: "destroy, disgust, disorient, intimidate", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Minion</b>: The Thrall is defeated when they take any damage. For every 13 damage a PC deals to the Thrall, defeat an additional Minion within range the attack would succeed against.", "<span class='cost-tag fear'>1 Fear</span> <b>Group Attack</b>: Spend a Fear to choose a target and spotlight all Outer Realm Thralls within Close range of them. Those Minions move into Melee range of the target and make one shared attack roll. On a success, they deal 11 physical damage each. Combine this damage."] },
  "perfected_zombie": { env: "Undead", name: "Perfected Zombie", tier: "4", type: "Bruiser", diff: 20, atk: "+4", maxHp: 9, maxStress: 4, major: 40, severe: 70, weapon: "Greataxe", damageType: "Physical", dice: "4d12+15", motives: "consume, hound, maim, terrify", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Terrifying</b>: When the Zombie makes a successful attack, all PCs within Far range lose a Hope and you gain a Fear.", "<span class='cost-tag'>Passive</span> <b>Fearsome Presence</b>: PCs can't spend Hope to use features against the Zombie.", "<span class='cost-tag stress'>1 Stress</span> <b>Perfect Strike</b>: Mark a Stress to make a standard attack against all targets within Very Close range. Targets the Zombie succeeds against are Vulnerable until their next rest.", "<span class='cost-tag fear'>1 Fear</span> <b>Skilled Opportunist</b>: When another adversary deals damage to a target within Very Close range of the Zombie, you can spend a Fear to add the Zombie's standard attack damage to the damage roll."] },
  "realm_breaker": { env: "The Fallen", name: "Realm-breaker", tier: "4", type: "Solo", diff: 20, atk: "+7", maxHp: 8, maxStress: 5, major: 36, severe: 66, weapon: "Barbed Whip", damageType: "Physical", dice: "4d8+7", motives: "corrupt, dominate, punish, break the weak", experiences: "Conquest +3, History +2, Intimidation +3", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Realm-Breaker can be spotlighted up to two times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag'>Passive</span> <b>Firespite Plate Armor</b>: When the Realm-Breaker takes damage, reduce it by 2d10.", "<span class='cost-tag stress'>1 Stress</span> <b>Tormenting Lash</b>: Mark a Stress to make a standard attack against all targets within Very Close range. When a target uses armor to reduce damage from this attack, they must mark 2 Armor Slots.", "<span class='cost-tag'>Passive</span> <b>All-Consuming Rage</b>: Countdown (Decreasing 8). When the Realm-Breaker is in the spotlight for the first time, activate the countdown. When it triggers, create a torrent of incarnate rage that rends flesh from bone. All targets within Far range must make a Presence Reaction Roll. Targets who fail take 2d6+10 direct magic damage. Targets who succeed take half damage. For each HP marked from this damage, summon a Fallen Shock Troop within Very Close range of the target who marked that HP. If the countdown ever decreases its maximum value to 0, the Realm-Breaker marks their remaining HP and all targets within Far range must mark all remaining HP and make a death move.", "<span class='cost-tag'>Passive</span> <b>Doombringer</b>: When a target marks HP from an attack by the Realm-Breaker, all PCs within Far range of the target must lose a Hope.", "<span class='cost-tag'>Passive</span> <b>I Have Never Known Defeat</b>: When the Realm-Breaker marks their last HP, replace them with the Undefeated Champion and immediately spotlight them.:"] },
  "volcanic_dragon_ashen_tyrant": { env: "Beasts & Solos", name: "Volcanic Dragon: Ashen Tyrant", tier: "4", type: "Solo", diff: 18, atk: "+10", maxHp: 8, maxStress: 5, major: 29, severe: 55, weapon: "Claws and Teeth", damageType: "Physical", dice: "4d12+15", motives: "choke, fl y, intimidate, kill or be killed", experiences: "Hunt from Above +5", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Ashen Tyrant can be spotlighted up to four times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag stress'>1 Stress</span> <b>Cornered</b>: Mark a Stress instead of spending a Fear to spotlight the Ashen Tyrant.", "<span class='cost-tag'>Passive</span> <b>Injured Wings</b>: While flying, the Ashen Tyrant gains a +1 bonus to their Difficulty.", "<span class='cost-tag stress'>Mark HP</span> <b>Ashes to Ashes</b>: When a PC rolls a failure while within Close range of the Ashen Tyrant, they lose a Hope and you gain a Fear. If the PC can't lose a Hope, they must mark a HP.", "<span class='cost-tag stress'>1 Stress</span> <b>Desperate Rampage</b>: Mark a Stress to make an attack against all targets within Close range. Targets the Ashen Tyrant succeeds against take 2d20+2 physical damage, are knocked back to Close range of where they were, and must mark a Stress.", "<span class='cost-tag fear'>1 Fear</span> <b>Ashen Cloud</b>: Spend a Fear to smash the ground and kick up ash within Far range. While within the ash cloud, a target has disadvantage on action rolls. The ash cloud clears the next time an adversary is spotlighted.", "<span class='cost-tag fear'>1 Fear</span> <b>Apocalyptic Thrashing</b>: Countdown (1d12). Spend a Fear to activate. It ticks down when a PC rolls with Fear. When it triggers, the Ashen Tyrant thrashes about, causing environmental damage (such as an earthquake, avalanche, or collapsing walls). All targets within Far range must make a Strength Reaction Roll. Targets who fail take 2d10+10 physical damage and are Restrained by the rubble until they break free with a successful Strength Roll. Targets who succeed take half damage. If the Ashen Tyrant is defeated while this countdown is active, trigger the countdown immediately as the destruction caused by their death throes."] },
  "volcanic_dragon_molten_scourge": { env: "Beasts & Solos", name: "Volcanic Dragon: Molten Scourge", tier: "4", type: "Solo", diff: 20, atk: "+9", maxHp: 7, maxStress: 5, major: 30, severe: 58, weapon: "Lava-Coated Claws", damageType: "Physical", dice: "4d12+4", motives: "douse with lava, incinerate, repel invaders, reposition", experiences: "Hunt from Above +5", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Molten Scourge can be spotlighted up to three times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag'>Passive</span> <b>Cracked Scales</b>: When the Molten Scourge takes damage, roll a number of d6s equal to HP marked. For each result of 4 or higher, you gain a Fear.", "<span class='cost-tag stress'>1 Stress</span> <b>Shattering Might</b>: Mark a Stress to make an attack against a target within Very Close range. On a success, the target takes 4d8+1 physical damage, loses a Hope, and is knocked back to Close range. The Molten Scourge clears a Stress.", "<span class='cost-tag fear'>1 Fear</span> <b>Eruption</b>: Spend a Fear to erupt lava from beneath the Molten Scourge's scales, fi lling the area within Very Close range with molten lava. All targets in that area must succeed on an Agility Reaction Roll or take 4d6+6 physical damage and be knocked back to Close range. This area remains lava. When a creature other than the Molten Scourge enters that area or acts while inside of it, they must mark 6 HP.", "<span class='cost-tag stress'>1 Stress</span> <b>Volcanic Breath</b>: When the Molten Scourge takes Major damage, roll a d10. On a result of 8 or higher, the Molten Scourge breathes a fl ow of lava in front of them within Far range. All targets in that area must make an Agility Reaction Roll. Targets who fail take 2d10+4 physical damage, mark 1d4 Stress, and are Vulnerable until they clear a Stress. Targets who succeed take half damage and must mark a Stress.", "<span class='cost-tag'>Passive</span> <b>Lava Splash</b>: When the Molten Scourge takes Severe damage from an attack within Very Close range, molten blood gushes from the wound and deals 2d10+4 direct physical damage to the attacker.", "<span class='cost-tag'>Passive</span> <b>Ashen Vengeance</b>: When the Molten Scourge marks their last HP, replace them with the Ashen Tyrant and immediately spotlight them."] },
  "volcanic_dragon_obsidian_predator": { env: "Beasts & Solos", name: "Volcanic Dragon: Obsidian Predator", tier: "4", type: "Solo", diff: 19, atk: "+8", maxHp: 6, maxStress: 5, major: 33, severe: 65, weapon: "Obsidian Claws", damageType: "Physical", dice: "4d10+4", motives: "defend lair, dive-bomb, fl y, hunt, intimidate", experiences: "Hunt from Above +5", features: ["<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Obsidian Predator can be spotlighted up to two times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag'>Passive</span> <b>Flying</b>: While flying, the Obsidian Predator gains a +3 bonus to their Difficulty.", "<span class='cost-tag'>Passive</span> <b>Obsidian Scales</b>: The Obsidian Predator is resistant to physical damage.", "<span class='cost-tag stress'>1 Stress</span> <b>Avalanche Tail</b>: Mark a Stress to make an attack against all targets within Close range. Targets the Obsidian Predator succeeds against take 4d6+4 physical damage and are knocked back to Far range and Vulnerable until their next roll with Hope.", "<span class='cost-tag stress'>1 Stress</span> <b>Dive-Bomb</b>: If the Obsidian Predator is flying, mark a Stress to choose a point within Far range. Move to that point and make an attack against all targets within Very Close range. Targets the Obsidian Predator succeeds against take 2d10+6 physical damage and must mark a Stress and lose a Hope.", "<span class='cost-tag'>Passive</span> <b>Erupting Rage</b>: When the Obsidian Predator marks their last HP, replace them with the Molten Scourge and immediately spotlight them."] },
  "zombie_legion": { env: "Undead", name: "Zombie Legion", tier: "4", type: "Horde", diff: 17, atk: "+2", maxHp: 8, maxStress: 5, major: 25, severe: 45, weapon: "Tentacles", damageType: "Physical", dice: "4d6+10", motives: "consume brain, shred flesh, surround", experiences: "", features: ["<span class='cost-tag'>Passive</span> <b>Horde</b>: When the Legion has marked half or more of their HP, their standard attack deals 2d6+5 physical damage instead.", "<span class='cost-tag'>Passive</span> <b>Unyielding</b>: The Legion has resistance to physical damage.", "<span class='cost-tag'>Passive</span> <b>Relentless</b>: The Legion can be spotlighted up to two times per GM turn. Spend Fear as usual to spotlight them.", "<span class='cost-tag stress'>1 Stress</span> <b>Overwhelm</b>: When the Legion takes Minor damage from an attack within Melee range, you can mark a Stress to make a standard attack with advantage against the attacker."] }
};
